window.bibleReaderData = window.bibleReaderData || {chapters:{}};
window.bibleReaderData.chapters = window.bibleReaderData.chapters || {};
window.bibleReaderData.chapters['1SA'] = window.bibleReaderData.chapters['1SA'] || {};
(function(chapters){ for (const c in chapters){ window.bibleReaderData.chapters['1SA'][c]=window.bibleReaderData.chapters['1SA'][c]||{}; Object.assign(window.bibleReaderData.chapters['1SA'][c], chapters[c]); } })({"1":{"fa":[{"v":1,"t":"و مردی بود از رامه تایم صوفیم از کوهستان افرایم، مسمی به القانه بن یروحام بن الیهو بن توحو بن صوف. و او افرایمی بود."},{"v":2,"t":"و او دو زن داشت. اسم یکی حنا و اسم دیگری فننه بود. و فننه اولاد داشت لیکن حنا رااولاد نبود."},{"v":3,"t":"و آن مرد هر سال برای عبادت نمودن وقربانی گذرانیدن برای یهوه صبایوت از شهر خودبه شیلوه می‌آمد، و حفنی و فینحاس دو پسرعیلی، کاهنان خداوند در آنجا بودند."},{"v":4,"t":"و چون روزی می‌آمد که القانه قربانی می‌گذرانید، به زن خود فننه و همه پسران و دختران خود قسمت هامی داد."},{"v":5,"t":"و اما به حنا قسمت مضاعف می‌داد زیراکه حنا را دوست می‌داشت، اگر‌چه خداوند رحم او را بسته بود."},{"v":6,"t":"و هئوی وی او را نیز سخت می‌رنجانید به حدی که وی را خشمناک می‌ساخت، چونکه خداوند رحم او را بسته بود."},{"v":7,"t":"و همچنین سال به سال واقع می‌شد که چون حنابه خانه خدا می‌آمد، فننه همچنین او رامی رنجانید و او گریه نموده، چیزی نمی خورد."},{"v":8,"t":"و شوهرش، القانه، وی را می‌گفت: «ای حنا چراگریانی و چرا نمی خوری و دلت چرا غمگین است؟ آیا من برای تو از ده پسر بهتر نیستم؟»"},{"v":9,"t":"و بعد از اکل و شرب نمودن ایشان در شیلوه، حنا برخاست و عیلی کاهن بر کرسی خود نزد ستونی در هیکل خدا نشسته بود."},{"v":10,"t":"و او به تلخی جان نزد خداوند دعا کرد، و زارزار بگریست."},{"v":11,"t":"ونذر کرده، گفت: «ای یهوه صبایوت اگر فی الواقع به مصیبت کنیز خود نظر کرده، مرا بیاد آوری وکنیزک خود را فراموش نکرده، اولاد ذکوری به کنیز خود عطا فرمایی، او را تمامی ایام عمرش به خداوند خواهم داد، و استره بر سرش نخواهدآمد.»"},{"v":12,"t":"و چون دعای خود را به حضور خداوندطول داد عیلی دهن او را ملاحظه کرد."},{"v":13,"t":"و حنادر دل خود سخن می‌گفت، و لبهایش فقط، متحرک بود و آوازش مسموع نمی شد، و عیلی گمان برد که مست است."},{"v":14,"t":"پس عیلی وی راگفت: «تا به کی مست می‌شوی؟ شرابت را از خوددور کن.»"},{"v":15,"t":"و حنا در جواب گفت: «نی آقایم، بلکه زن شکسته روح هستم، و شراب و مسکرات ننوشیده‌ام، بلکه جان خود را به حضور خداوندریخته‌ام."},{"v":16,"t":"کنیز خود را از دختران بلیعال مشمار، زیرا که از کثرت غم و رنجیدگی خود تابحال می‌گفتم.»"},{"v":17,"t":"عیلی در جواب گفت: «به سلامتی برو و خدای اسرائیل مسالتی را که از اوطلب نمودی، تو را عطا فرماید.»"},{"v":18,"t":"گفت: «کنیزت در نظرت التفات یابد.» پس آن زن راه خود را پیش گرفت و می‌خورد و دیگر ترشرونبود."},{"v":19,"t":"و ایشان بامدادان برخاسته، به حضور خداوند عبادت کردند و برگشته، به خانه خویش به رامه آمدند، و القانه زن خود حنا را بشناخت وخداوند او را به یاد آورد."},{"v":20,"t":"و بعد از مرور ایام حنا حامله شده، پسری زایید و او را سموئیل نام نهاد، زیرا گفت: «او را از خداوند سوال نمودم.»"},{"v":21,"t":"و شوهرش القانه با تمامی اهل خانه‌اش رفت تا قربانی سالیانه و نذر خود را نزد خداوندبگذراند."},{"v":22,"t":"و حنا نرفت زیرا که به شوهر خودگفته بود تا پسر از شیر باز داشته نشود، نمی آیم، آنگاه او را خواهم آورد و به حضور خداوندحاضر شده، آنجا دائم خواهد ماند."},{"v":23,"t":"شوهرش القانه وی را گفت: «آنچه در نظرت پسند آید، بکن، تا وقت باز داشتنش از شیر بمان، لیکن خداوند کلام خود را استوار نماید.» پس آن زن ماند و تا وقت بازداشتن پسر خود از شیر، او راشیر می‌داد."},{"v":24,"t":"و چون او را از شیر باز داشته بود، وی را باسه گاو و یک ایفه آرد و یک مشک شراب با خودآورده، به خانه خداوند در شیلوه رسانید و آن پسر کوچک بود."},{"v":25,"t":"و گاو را ذبح نمودند، و پسررا نزد عیلی آوردند."},{"v":26,"t":"و حنا گفت: «عرض می‌کنم‌ای آقایم! جانت زنده باد‌ای آقایم! من آن زن هستم که در اینجا نزد تو ایستاده، از خداوندمسئلت نمودم."},{"v":27,"t":"برای این پسر مسالت نمودم وخداوند مسالت مرا که از او طلب نموده بودم، به من عطا فرموده است."},{"v":28,"t":"و من نیز او را برای خداوند وقف نمودم؛ تمام ایامی که زنده باشدوقف خداوند خواهد بود.» پس در آنجا خداوند را عبادت نمودند."}]},"2":{"fa":[{"v":1,"t":"و حنا دعا نموده، گفت: «دل من در خداوند وجد می‌نماید. و شاخ من در نزد خداوند برافراشته شده. و دهانم بر دشمنانم وسیع گردیده است. زیرا که در نجات تو شادمان هستم."},{"v":2,"t":"مثل یهوه قدوسی نیست. زیرا غیر از تو کسی نیست. و مثل خدای ما صخره‌ای نیست."},{"v":3,"t":"سخنان تکبرآمیز دیگر مگویید. و غرور از دهان شما صادر نشود. زیرا یهوه خدای علام است. وبه او اعمال، سنجیده می‌شود."},{"v":4,"t":"کمان جباران را شکسته است. و آنانی که می‌لغزیدند، کمر آنها به قوت بسته شد."},{"v":5,"t":"سیرشدگان، خویشتن را برای نان اجیر ساختند. و کسانی که گرسنه بودند، استراحت یافتند. بلکه زن نازا هفت فرزند زاییده است. و آنکه اولادبسیار داشت، زبون گردیده."},{"v":6,"t":"خداوند می‌میراند و زنده می‌کند؛ به قبر فرودمی آورد و برمی خیزاند."},{"v":7,"t":"خداوند فقیر می‌سازد و غنی می‌گرداند؛ پست می‌کند و بلند می‌سازد."},{"v":8,"t":"فقیر را از خاک برمی افرازد. و مسکین را از مزبله برمی دارد تا ایشان را با امیران بنشاند. و ایشان راوارث کرسی جلال گرداند. زیرا که ستونهای زمین از آن خداوند است. و ربع مسکون را بر آنهااستوار نموده است."},{"v":9,"t":"پایهای مقدسین خود را محفوظ می‌دارد. اماشریران در ظلمت خاموش خواهند شد، زیرا که انسان به قوت خود غالب نخواهد آمد."},{"v":10,"t":"آنانی که با خداوند مخاصمه کنند، شکسته خواهند شد. او بر ایشان از آسمان صاعقه خواهدفرستاد. خداوند، اقصای زمین را داوری خواهدنمود، و به پادشاه خود قوت خواهد بخشید. وشاخ مسیح خود را بلند خواهد گردانید.»"},{"v":11,"t":"پس القانه به خانه خود به راما رفت و آن پسر به حضور عیلی کاهن، خداوند را خدمت می‌نمود."},{"v":12,"t":"و پسران عیلی از بنی بلیعال بودند وخداوند را نشناختند."},{"v":13,"t":"و عادت کاهنان با قوم این بود که چون کسی قربانی می‌گذرانید هنگامی که گوشت پخته می‌شد، خادم کاهن با چنگال سه دندانه در دست خود می‌آمد"},{"v":14,"t":"و آن را به تاوه یامرجل یا دیگ یا پاتیل فرو برده، هر‌چه چنگال برمی آورد کاهن آن را برای خود می‌گرفت، وهمچنین با تمامی اسرائیل که در آنجا به شیلوه می‌آمدند، رفتار می‌نمودند."},{"v":15,"t":"و نیز قبل ازسوزانیدن پیه، خادم کاهن آمده، به کسی‌که قربانی می‌گذرانید، می‌گفت: «گوشت به جهت کباب برای کاهن بده، زیرا گوشت پخته از تونمی گیرد بلکه خام.»"},{"v":16,"t":"و آن مرد به وی می‌گفت: «پیه را اول بسوزانند و بعد هر‌چه دلت می‌خواهدبرای خود بگیر.» او می‌گفت: «نی، بلکه الان بده، والا به زور می‌گیرم.»"},{"v":17,"t":"پس گناهان آن جوانان به حضور خداوند بسیار عظیم بود، زیرا که مردمان هدایای خداوند را مکروه می‌داشتند."},{"v":18,"t":"و اما سموئیل به حضور خداوند خدمت می کرد، و او پسر کوچک بود و بر کمرش ایفودکتان بسته بود."},{"v":19,"t":"و مادرش برای وی جبه کوچک می‌ساخت، و آن را سال به سال همراه خودمی آورد، هنگامی که با شوهر خود برمی آمد تاقربانی سالیانه را بگذرانند."},{"v":20,"t":"و عیلی القانه وزنش را برکت داده، گفت: «خداوند تو را از این زن به عوض عاریتی که به خداوند داده‌ای، اولادبدهد.» پس به مکان خود رفتند."},{"v":21,"t":"و خداوند از حنا تفقد نمود و او حامله شده، سه پسر و دو دختر زایید، و آن پسر، سموئیل به حضور خداوند نمو می‌کرد."},{"v":22,"t":"و عیلی بسیار سالخورده شده بود، و هر‌چه پسرانش با تمامی اسرائیل عمل می‌نمودند، می‌شنید، و اینکه چگونه با زنانی که نزد در خیمه اجتماع خدمت می‌کردند، می‌خوابیدند."},{"v":23,"t":"پس به ایشان گفت: «چرا چنین کارها می‌کنید زیرا که اعمال بد شما را از تمامی این قوم می‌شنوم."},{"v":24,"t":"چنین مکنید‌ای پسرانم زیرا خبری که می‌شنوم خوب نیست، شما باعث عصیان قوم خداوند می‌باشید."},{"v":25,"t":"اگر شخصی بر شخصی گناه ورزد خدا او را داوری خواهد کرد اما اگرشخصی بر خداوند گناه ورزد، کیست که برای وی شفاعت نماید؟» اما ایشان سخن پدر خود رانشنیدند، زیرا خداوند خواست که ایشان راهلاک سازد."},{"v":26,"t":"و آن پسر، سموئیل، نمو می‌یافت و هم نزدخداوند و هم نزد مردمان پسندیده می‌شد."},{"v":27,"t":"و مرد خدایی نزد عیلی آمده، به وی گفت: «خداوند چنین می‌گوید: آیا خود را بر خاندان پدرت هنگامی که ایشان در مصر در خانه فرعون بودند، ظاهر نساختم؟"},{"v":28,"t":"و آیا او را از جمیع اسباط اسرائیل برنگزیدم تا کاهن من بوده، نزدمذبح من بیاید. و بخور بسوزاند و به حضور من ایفود بپوشد، وآیا جمیع هدایای آتشین بنی‌اسرائیل را به خاندان پدرت نبخشیدم؟"},{"v":29,"t":"پس چرا قربانی‌ها و هدایای مرا که در مسکن خود امر فرمودم، پایمال می‌کنید و پسران خود رازیاده از من محترم می‌داری، تا خویشتن را ازنیکوترین جمیع هدایای قوم من، اسرائیل فربه سازی."},{"v":30,"t":"بنابراین یهوه، خدای اسرائیل می‌گوید: البته گفتم که خاندان تو و خاندان پدرت به حضور من تا به ابد سلوک خواهند نمود، لیکن الان خداوند می‌گوید: حاشا از من! زیرا آنانی که مرا تکریم نمایند، تکریم خواهم نمود و کسانی که مرا حقیر شمارند، خوار خواهند شد."},{"v":31,"t":"اینک ایامی می‌آید که بازوی تو را و بازوی خاندان پدرتو را قطع خواهم نمود که مردی پیر در خانه تویافت نشود."},{"v":32,"t":"و تنگی مسکن مرا خواهی دید، در هر احسانی که به اسرائیل خواهد شد، و مردی پیر در خانه تو ابد نخواهد بود."},{"v":33,"t":"و شخصی رااز کسان تو که از مذبح خود قطع نمی نمایم برای کاهیدن چشم تو و رنجانیدن دلت خواهد بود، وجمیع ذریت خانه تو در جوانی خواهند مرد."},{"v":34,"t":"واین برای تو علامت باشد که بر دو پسرت حفنی وفینحاس واقع می‌شود که هر دوی ایشان در یک روز خواهند مرد."},{"v":35,"t":"و کاهن امینی به جهت خودبرپا خواهم داشت که موافق دل و جان من رفتارخواهد نمود، و برای او خانه مستحکمی بنا خواهم کرد، و به حضور مسیح من پیوسته سلوک خواهد نمود."},{"v":36,"t":"و واقع خواهد شد که هر‌که درخانه تو باقی ماند، آمده، نزد او به جهت پاره‌ای نقره و قرص نانی تعظیم خواهد نمود و خواهدگفت: تمنا اینکه مرا به یکی از وظایف کهانت بگذار تا لقمه‌ای نان بخورم.»"}]},"3":{"fa":[{"v":1,"t":"و آن پسر، سموئیل، به حضور عیلی، خداوند را خدمت می‌نمود، و در آن روزهاکلام خداوند نادر بود و رویا مکشوف نمی شد."},{"v":2,"t":"و در آن زمان واقع شد که چون عیلی در جایش خوابیده بود و چشمانش آغاز تار شدن نموده، نمی توانست دید،"},{"v":3,"t":"و چراغ خدا هنوز خاموش نشده، و سموئیل در هیکل خداوند، جایی که تابوت خدا بود، می‌خوابید،"},{"v":4,"t":"خداوند سموئیل را خواند و او گفت: «لبیک.»"},{"v":5,"t":"پس نزد عیلی شتافته، گفت: «اینک حاضرم زیرا مرا خواندی.» او گفت: «نخواندم، برگشته، بخواب.» و او برگشته، خوابید."},{"v":6,"t":"و خداوند بار دیگر خواند: «ای سموئیل!» وسموئیل برخاسته، نزد عیلی آمده، گفت: «اینک حاضرم زیرا مرا خواندی.» او گفت: «ای پسرم تورا نخواندم، برگشته، بخواب.»"},{"v":7,"t":"و سموئیل، خداوند را هنوز نمی شناخت وکلام خداوند تا حال بر او منکشف نشده بود."},{"v":8,"t":"وخداوند باز سموئیل را بار سوم خواند و اوبرخاسته، نزد عیلی آمده، گفت: «اینک حاضرم زیرا مرا خواندی.» آنگاه عیلی فهمید که یهوه، پسر را خوانده است."},{"v":9,"t":"و عیلی به سموئیل گفت: «برو و بخواب و اگر تو را بخواند، بگو‌ای خداوندبفرما زیرا که بنده تو می‌شنود.» پس سموئیل رفته، در جای خود خوابید."},{"v":10,"t":"و خداوند آمده، بایستاد و مثل دفعه های پیش خواند: «ای سموئیل! ای سموئیل!» سموئیل گفت: «بفرما زیرا که بنده تو می‌شنود.»"},{"v":11,"t":"و خداوند به سموئیل گفت: «اینک من کاری در اسرائیل می‌کنم که گوشهای هر‌که بشنود، صدا خواهد داد."},{"v":12,"t":"در آن روز هر‌چه درباره خانه عیلی گفتم بر او اجرا خواهم داشت، و شروع نموده، به انجام خواهم رسانید."},{"v":13,"t":"زیرا به او خبردادم که من بر خانه او تا به ابد داوری خواهم نمودبه‌سبب گناهی که می‌داند، چونکه پسرانش برخود لعنت آوردند و او ایشان را منع ننمود."},{"v":14,"t":"بنابراین برای خاندان عیلی قسم خوردم که گناه خاندان عیلی به قربانی و هدیه، تا به ابد کفاره نخواهد شد.»"},{"v":15,"t":"و سموئیل تا صبح خوابید و درهای خانه خداوند را باز کرد، و سموئیل ترسید که عیلی رااز رویا اطلاع دهد."},{"v":16,"t":"اما عیلی سموئیل راخوانده، گفت: «ای پسرم سموئیل!» او گفت: «لبیک»"},{"v":17,"t":"گفت: «چه سخنی است که به تو گفته است؟ آن را از من مخفی مدار. خدا با تو چنین بلکه زیاده از این عمل نماید، اگر از هر‌آنچه به توگفته است چیزی از من مخفی داری.»"},{"v":18,"t":"پس سموئیل همه‌چیز را برای او بیان کرد و چیزی ازآن مخفی نداشت. و او گفت «خداوند است آنچه در نظر او پسند آید بکند.»"},{"v":19,"t":"و سموئیل بزرگ می‌شد و خداوند با وی می‌بود و نمی گذاشت که یکی از سخنانش بر زمین بیفتد."},{"v":20,"t":"و تمامی اسرائیل از دان تا بئرشبع دانستند که سموئیل برقرار شده است تا نبی خداوند باشد."},{"v":21,"t":"و خداوند بار دیگر در شیلوه ظاهر شد، زیرا که خداوند در شیلوه خود را برسموئیل به کلام خداوند ظاهر ساخت."}]},"4":{"fa":[{"v":1,"t":"و کلام سموئیل به تمامی اسرائیل رسید. واسرائیل به مقابله فلسطینیان در جنگ بیرون آمده، نزد ابن عزر اردو زدند، و فلسطینیان در افیق فرود آمدند."},{"v":2,"t":"و فلسطینیان در مقابل اسرائیل صف آرایی کردند، و چون جنگ درپیوستند، اسرائیل از حضور فلسطینیان شکست خوردند، و در معرکه به قدر چهار هزار نفر را درمیدان کشتند."},{"v":3,"t":"و چون قوم به لشکرگاه رسیدند، مشایخ اسرائیل گفتند: «چرا امروز خداوند ما رااز حضور فلسطینیان شکست داد؟ پس تابوت عهد خداوند را از شیلوه نزد خود بیاوریم تا درمیان ما آمده، ما را از دست دشمنان ما نجات دهد.»"},{"v":4,"t":"و قوم به شیلوه فرستاده، تابوت عهد یهوه صبایوت را که در میان کروبیان ساکن است از آنجاآوردند، و دو پسر عیلی حفنی و فینحاس درآنجا با تابوت عهد خدا بودند."},{"v":5,"t":"و چون تابوت عهد خداوند به لشکرگاه داخل شد، جمیع اسرائیل صدای بلند زدند به حدی که زمین متزلزل شد."},{"v":6,"t":"و چون فلسطینیان آواز صدا را شنیدند، گفتند: «این آواز صدای بلنددر اردوی عبرانیان چیست؟» پس فهمیدند که تابوت خداوند به اردو آمده است."},{"v":7,"t":"و فلسطینیان ترسیدند زیرا گفتند: «خدا به اردو آمده است» و گفتند: «وای بر ما، زیرا قبل از این‌چنین چیزی واقع نشده است!"},{"v":8,"t":"وای بر ما، کیست که ما را ازدست این خدایان زورآور رهایی دهد، همین خدایانند که مصریان را در بیابان به همه بلایا مبتلاساختند."},{"v":9,"t":"‌ای فلسطینیان خویشتن را تقویت داده، مردان باشید مبادا عبرانیان را بندگی کنید، چنانکه ایشان شما را بندگی نمودند، پس مردان شوید و جنگ کنید.»"},{"v":10,"t":"پس فلسطینیان جنگ کردند و اسرائیل شکست خورده، هر یک به خیمه خود فرار کردندو کشتار بسیار عظیمی شد، و از اسرائیل سی هزار پیاده کشته شدند."},{"v":11,"t":"و تابوت خدا گرفته شد، و دو پسر عیلی حفنی و فینحاس کشته شدند."},{"v":12,"t":"و مردی بنیامینی از لشکر دویده، در همان روز با جامه دریده و خاک بر سر ریخته، به شیلوه آمد."},{"v":13,"t":"و چون وارد شد اینک عیلی به کنار راه برکرسی خود مراقب نشسته، زیرا که دلش درباره تابوت خدا مضطرب می‌بود. و چون آن مرد به شهر داخل شده، خبر داد، تمامی شهر نعره زدند."},{"v":14,"t":"و چون عیلی آواز نعره را شنید، گفت: «این آواز هنگامه چیست؟» پس آن مرد شتافته، عیلی را خبر داد."},{"v":15,"t":"و عیلی نود و هشت ساله بود وچشمانش تار شده، نمی توانست دید."},{"v":16,"t":"پس آن مرد به عیلی گفت: «منم که از لشکرآمده، و من امروز از لشکر فرار کرده‌ام.» گفت: «ای پسرم کار چگونه گذشت؟»"},{"v":17,"t":"و آن خبرآورنده در جواب گفت: «اسرائیل از حضورفلسطینیان فرار کردند، و شکست عظیمی هم درقوم واقع شد، و نیز دو پسرت حفنی و فینحاس مردند و تابوت عهد خدا گرفته شد.»"},{"v":18,"t":"و چون ازتابوت خدا خبر داد، عیلی از کرسی خود به پهلوی دروازه به پشت افتاده، گردنش بشکست وبمرد، زیرا که مردی پیر و سنگین بود و چهل سال بر اسرائیل داوری کرده بود."},{"v":19,"t":"و عروس او، زن فینحاس که حامله و نزدیک به زاییدن بود، چون خبر‌گرفتن تابوت خدا و مرگ پدر شوهرش وشوهرش را شنید، خم شده، زایید زیرا که درد زه او را بگرفت."},{"v":20,"t":"و در وقت مردنش زنانی که نزدوی ایستاده بودند، گفتند: «مترس زیرا که پسرزاییدی، » اما او جواب نداد و اعتنا ننمود."},{"v":21,"t":"وپسر را ایخابود نام نهاده، گفت: «جلال از اسرائیل زایل شد»، چونکه تابوت خدا گرفته شده بود و به‌سبب پدر شوهرش و شوهرش."},{"v":22,"t":"پس گفت: «جلال از اسرائیل زایل شد زیرا که تابوت خداگرفته شده است.»"}]},"5":{"fa":[{"v":1,"t":"و فلسطینیان تابوت خدا را گرفته، آن را ازابن عزر به اشدود آوردند."},{"v":2,"t":"و فلسطینیان تابوت خدا را گرفته، آن را به خانه داجون درآورده، نزدیک داجون گذاشتند."},{"v":3,"t":"و بامدادان چون اشدودیان برخاستند، اینک داجون به حضور تابوت خداوند رو به زمین افتاده بود. وداجون را برداشته، باز در جایش برپا داشتند."},{"v":4,"t":"ودر فردای آن روز چون صبح برخاستند، اینک داجون به حضور تابوت خداوند رو به زمین افتاده، و سر داجون و دو دستش بر آستانه قطع شده، و تن داجون فقط از او باقی‌مانده بود."},{"v":5,"t":"ازاین جهت کاهنان داجون و هر‌که داخل خانه داجون می‌شود تا امروز بر آستانه داجون دراشدود پا نمی گذرد."},{"v":6,"t":"و دست خداوند بر اهل اشدود سنگین شده، ایشان را تباه ساخت و ایشان را هم اشدود و هم نواحی آن را به خراجها مبتلا ساخت."},{"v":7,"t":"و چون مردان اشدود دیدند که چنین است گفتند تابوت خدای اسرائیل با ما نخواهد ماند، زیرا که دست او بر ما و بر خدای ما، داجون سنگین است."},{"v":8,"t":"پس فرستاده، جمیع سروران فلسطینیان را نزد خودجمع کرده، گفتند: «با تابوت خدای اسرائیل چه کنیم؟» گفتند: «تابوت خدای اسرائیل به جت منتقل شود.» پس تابوت خدای اسرائیل را به آنجا بردند."},{"v":9,"t":"و واقع شد بعد از نقل کردن آن که دست خداوند بر آن شهر به اضطراب بسیارعظیمی دراز شده، مردمان شهر را از خرد و بزرگ مبتلا ساخته، خراجها بر ایشان منتفخ شد."},{"v":10,"t":"پس تابوت خدا را به عقرون بردند و به مجرد ورودتابوت خدا به عقرون، اهل عقرون فریاد کرده، گفتند: «تابوت خدای اسرائیل را نزد ما آوردند تاما را و قوم ما را بکشند.»"},{"v":11,"t":"پس فرستاده، جیمع سروران فلسطینیان را جمع کرده، گفتند: «تابوت خدای اسرائیل را روانه کنید تا به‌جای خودبرگردد و ما را و قوم ما را نکشد زیرا که در تمام شهر هنگامه مهلک بود، و دست خدا در آنجابسیار سنگین شده بود."},{"v":12,"t":"و آنانی که نمردند به خراجها مبتلا شدند، و فریاد شهر تا به آسمان بالارفت."}]},"6":{"fa":[{"v":1,"t":"و تابوت خداوند در ولایت فلسطینیان هفت ماه ماند."},{"v":2,"t":"و فلسطینیان، کاهنان وفالگیران خود را خوانده، گفتند: «با تابوت خداوند چه کنیم؟ ما را اعلام نمایید که آن را به‌جایش با چه چیز بفرستیم.»"},{"v":3,"t":"گفتند: «اگر تابوت خدای اسرائیل را بفرستید آن را خالی مفرستید، بلکه قربانی جرم البته برای او بفرستید، آنگاه شفاخواهید یافت، و بر شما معلوم خواهد شد که ازچه سبب دست او از شما برداشته نشده است.»"},{"v":4,"t":"ایشان گفتند: «چه قربانی جرم برای اوبفرستیم؟»"},{"v":5,"t":"پس تماثیل خراجهای خود و تماثیل موشهای خود را که زمین را خراب می‌کنند بسازید، وخدای اسرائیل را جلال دهید که شاید دست خود را از شما و از خدایان شما و از زمین شمابردارد."},{"v":6,"t":"و چرا دل خود را سخت سازید، چنانکه مصریان و فرعون دل خود را سخت ساختند؟ آیابعد از آنکه در میان ایشان کارهای عجیب کرده بود ایشان را رها نکردند که رفتند؟"},{"v":7,"t":"پس الان ارابه تازه بسازید و دو گاو شیرده را که یوغ برگردن ایشان نهاده نشده باشد بگیرید، و دو گاو رابه ارابه ببندید و گوساله های آنها را از عقب آنها به خانه برگردانید."},{"v":8,"t":"و تابوت خداوند را گرفته، آن رابر ارابه بنهید و اسباب طلا را که به جهت قربانی جرم برای او می‌فرستید در صندوقچه‌ای به پهلوی آن بگذارید، و آن را رها کنید تا برود."},{"v":9,"t":"ونظر کنید اگر به راه سرحد خود به سوی بیت شمس برود، بدانید اوست که این بلای عظیم را بر ما وارد گردانیده است، و اگرنه، پس خواهیددانست که دست او ما را لمس نکرده است، بلکه آنچه بر ما واقع شده است، اتفاقی است.»"},{"v":10,"t":"پس آن مردمان چنین کردند و دو گاوشیرده را گرفته، آنها را به ارابه بستند، وگوساله های آنها را در خانه نگاه داشتند."},{"v":11,"t":"و تابوت خداوند و صندوقچه را با موشهای طلا وتماثیل خراجهای خود بر ارابه گذاشتند."},{"v":12,"t":"وگاوان راه خود را راست گرفته، به راه بیت شمس روانه شدند و به شاهراه رفته، بانگ می‌زدند و به سوی چپ یا راست میل نمی نمودند، و سروران فلسطینیان در عقب آنها تا حد بیت شمس رفتند."},{"v":13,"t":"و اهل بیت شمس در دره گندم را درومی کردند، و چشمان خود را بلند کرده، تابوت رادیدند و از دیدنش خوشحال شدند."},{"v":14,"t":"و ارابه به مزرعه یهوشع بیت شمسی درآمده، در آنجابایستاد و سنگ بزرگی در آنجا بود. پس چوب ارابه را شکسته، گاوان را برای قربانی سوختنی به جهت خداوند گذرانیدند."},{"v":15,"t":"و لاویان تابوت خداوند و صندوقچه‌ای را که با آن بود و اسباب طلا داشت، پایین آورده، آنها را بر آن سنگ بزرگ نهادند و مردان بیت شمس در همان روز برای خداوند قربانی های سوختنی گذرانیدند و ذبایح ذبح نمودند."},{"v":16,"t":"و چون آن پنج سرور فلسطینیان این را دیدند، در همان روز به عقرون برگشتند."},{"v":17,"t":"و این است خراجهای طلایی که فلسطینیان به جهت قربانی جرم نزد خداوند فرستادند: برای اشدود یک، و برای غزه یک، و برای اشقلون یک، و برای جت یک، و برای عقرون یک."},{"v":18,"t":"وموشهای طلا بر‌حسب شماره جمیع شهرهای فلسطینیان که از املاک آن پنج سرور بود، چه ازشهرهای حصاردار و چه از دهات بیرون تا آن سنگ بزرگی که تابوت خداوند را بر آن گذاشتندکه تا امروز در مزرعه یهوشع بیت شمسی باقی است."},{"v":19,"t":"و مردمان بیت شمس را زد، زیرا که به تابوت خداوند نگریستند، پس پنجاه هزار وهفتاد نفر از قوم را زد و قوم ماتم گرفتند، چونکه خداوند خلق را به بلای عظیم مبتلا ساخته بود."},{"v":20,"t":"و مردمان بیت شمس گفتند: «کیست که به حضور این خدای قدوس یعنی یهوه می‌تواندبایستد و از ما نزد که خواهد رفت؟»"},{"v":21,"t":"پس رسولان نزد ساکنان قریه یعاریم فرستاده، گفتند: «فلسطینیان تابوت خداوند را پس فرستاده‌اند، بیایید و آن را نزد خود ببرید.»"}]},"7":{"fa":[{"v":1,"t":"خداوند را آوردند، و آن را به خانه ابیناداب در جبعه داخل کرده، پسرش العازار راتقدیس نمودند تا تابوت خداوند را نگاهبانی کند."},{"v":2,"t":"و از روزی که تابوت در قریه یعاریم ساکن شد، وقت طول کشید تا بیست سال گذشت، و بعداز آن خاندان اسرائیل برای پیروی خداوند جمع شدند."},{"v":3,"t":"و سموئیل تمامی خاندان اسرائیل را خطاب کرده، گفت: «اگر به تمامی دل به سوی خداوندبازگشت نمایید، و خدایان غیر و عشتاروت را ازمیان خود دور کنید، و دلهای خود را برای خداوند حاضر ساخته، او را تنها عبادت نمایید، پس او، شما را از دست فلسطینیان خواهدرهانید.»"},{"v":4,"t":"آنگاه بنی‌اسرائیل بعلیم و عشتاروت رادور کرده، خداوند را تنها عبادت نمودند."},{"v":5,"t":"و سموئیل گفت: «تمامی اسرائیل را درمصفه جمع کنید تا درباره شما نزد خداوند دعانمایم.»"},{"v":6,"t":"و در مصفه جمع شدند و آب کشیده، آن را به حضور خداوند ریختند، و آن روز راروزه داشته، در آنجا گفتند که بر خداوند گناه کرده‌ایم، و سموئیل بنی‌اسرائیل را در مصفه داوری نمود."},{"v":7,"t":"و چون فلسطینیان شنیدند که بنی‌اسرائیل درمصفه جمع شده‌اند، سروران فلسطینیان براسرائیل برآمدند، و بنی‌اسرائیل چون این راشنیدند، از فلسطینیان ترسیدند."},{"v":8,"t":"و بنی‌اسرائیل به سموئیل گفتند: «از تضرع نمودن برای ما نزدیهوه خدای ما ساکت مباش تا ما را از دست فلسطینیان برهاند.»"},{"v":9,"t":"و سموئیل بره شیرخواره گرفته، آن را به جهت قربانی سوختنی تمام برای خداوند گذرانید، و سموئیل درباره اسرائیل نزدخداوند تضرع نموده، خداوند او را اجابت نمود."},{"v":10,"t":"و چون سموئیل قربانی سوختنی رامی گذرانید، فلسطینیان برای مقاتله اسرائیل نزدیک آمدند، و در آن روز خداوند به صدای عظیم بر فلسطینیان رعد کرده، ایشان را منهزم ساخت، و از حضور اسرائیل شکست یافتند."},{"v":11,"t":"ومردان اسرائیل از مصفه بیرون آمدند و فلسطینیان را تعاقب نموده، ایشان را تا زیر بیت کار شکست دادند."},{"v":12,"t":"و سموئیل سنگی گرفته، آن را میان مصفه وسن برپا داشت و آن را ابن عزر نامیده، گفت: «تابحال خداوند ما را اعانت نموده است.»"},{"v":13,"t":"پس فلسطینیان مغلوب شدند، و دیگر به حدوداسرائیل داخل نشدند، و دست خداوند در تمامی روزهای سموئیل بر فلسطینیان سخت بود."},{"v":14,"t":"وشهرهایی که فلسطینیان از اسرائیل گرفته بودند، از عقرون تا جت، به اسرائیل پس دادند، و اسرائیل حدود آنها را از دست فلسطینیان رهانیدند، و در میان اسرائیل و اموریان صلح شد."},{"v":15,"t":"و سموئیل در تمام روزهای عمر خود براسرائیل داوری می‌نمود."},{"v":16,"t":"و هر سال رفته، به بیت ئیل و جلجال و مصفه گردش می‌کردند، و درتمامی این‌جاها بر اسرائیل داوری می‌نمود."},{"v":17,"t":"وبه رامه بر می‌گشت زیرا خانه‌اش در آنجا بود و درآنجا بر اسرائیل داوری می‌نمود، و مذبحی درآنجا برای خداوند بنا کرد."}]},"8":{"fa":[{"v":1,"t":"و واقع شد که چون سموئیل پیر شد، پسران خود را بر اسرائیل داوران ساخت."},{"v":2,"t":"و نام پسر نخست زاده‌اش یوئیل بود و نام دومینش ابیاه؛ و در بئرشبع داور بودند."},{"v":3,"t":"اماپسرانش به راه او رفتار نمی نمودند بلکه در‌پی سود رفته، رشوه می‌گرفتند و داوری را منحرف می‌ساختند."},{"v":4,"t":"پس جمیع مشایخ اسرائیل جمع شده، نزدسموئیل به رامه آمدند."},{"v":5,"t":"و او را گفتند: «اینک توپیر شده‌ای و پسرانت به راه تو رفتار نمی نمایند، پس الان برای ما پادشاهی نصب نما تا مثل سایرامتها بر ما حکومت نماید.»"},{"v":6,"t":"و این امر در نظرسموئیل ناپسند آمد، چونکه گفتند: «ما راپادشاهی بده تا بر ما حکومت نماید.» و سموئیل نزد خداوند دعا کرد."},{"v":7,"t":"و خداوند به سموئیل گفت: «آواز قوم را در هر‌چه به تو گفتند بشنو، زیرا که تو را ترک نکردند بلکه مرا ترک کردند تا برایشان پادشاهی ننمایم."},{"v":8,"t":"بر‌حسب همه اعمالی که از روزی که ایشان را از مصر بیرون آوردم، بجا آوردند و مرا ترک نموده، خدایان غیر را عبادت نمودند پس با تو نیز همچنین رفتار می‌نمایند."},{"v":9,"t":"پس الان آواز ایشان را بشنو لکن بر ایشان به تاکید شهادت بده، و ایشان را از رسم پادشاهی که بر ایشان حکومت خواهد نمود، مطلع ساز.»"},{"v":10,"t":"و سموئیل تمامی سخنان خداوند را به قوم که از او پادشاه خواسته بودند، بیان کرد."},{"v":11,"t":"وگفت: «رسم پادشاهی که بر شما حکم خواهدنمود این است که پسران شما را گرفته، ایشان را برارابه‌ها و سواران خود خواهد گماشت و پیش ارابه هایش خواهند دوید."},{"v":12,"t":"و ایشان را سرداران هزاره و سرداران پنجاهه برای خودخواهدساخت، و بعضی را برای شیار کردن زمینش و درویدن محصولش و ساختن آلات جنگش و اسباب ارابه هایش تعیین خواهد نمود."},{"v":13,"t":"و دختران شما را برای عطرکشی و طباخی وخبازی خواهد گرفت."},{"v":14,"t":"و بهترین مزرعه‌ها وتاکستانها و باغات زیتون شما را گرفته، به خادمان خود خواهد داد."},{"v":15,"t":"و عشر زراعات وتاکستانهای شما را گرفته، به خواجه‌سرایان وخادمان خود خواهد داد."},{"v":16,"t":"و غلامان و کنیزان ونیکوترین جوانان شما را و الاغهای شما را گرفته، برای کار خود خواهد گماشت."},{"v":17,"t":"و عشرگله های شما را خواهد گرفت و شما غلام اوخواهید بود."},{"v":18,"t":"و در آن روز از دست پادشاه خودکه برای خویشتن برگزیده‌اید فریاد خواهید کرد وخداوند در آن روز شما را اجابت نخواهد نمود.»"},{"v":19,"t":"اما قوم از شنیدن قول سموئیل ابا نمودند وگفتند: «نی بلکه می‌باید بر ما پادشاهی باشد."},{"v":20,"t":"تاما نیز مثل سایر امتها باشیم و پادشاه ما بر ماداوری کند، و پیش روی ما بیرون رفته، درجنگهای ما برای ما بجنگد.»"},{"v":21,"t":"و سموئیل تمامی سخنان قوم را شنیده، آنها را به سمع خداوند رسانید. و خداوند به سموئیل گفت: «آواز ایشان را بشنو و پادشاهی بر ایشان نصب نما.» پس سموئیل به مردمان اسرائیل گفت: «شماهرکس به شهر خود بروید.»"}]},"9":{"fa":[{"v":1,"t":"و مردی بود از بنیامین که اسمش قیس بن ابیئیل بن صرور بن بکورت بن افیح بود، و اوپسر مرد بنیامینی و مردی زورآور مقتدر بود."},{"v":2,"t":"واو را پسری شاول نام، جوانی خوش اندام بود که در میان بنی‌اسرائیل کسی از او خوش اندام تر نبودکه از کتفش تا به بالا از تمامی قوم بلندتر بود."},{"v":3,"t":"و الاغهای قیس پدر شاول گم شد. پس قیس به پسر خود شاول گفت: «الان یکی از جوانان خود را با خود گرفته، برخیز و رفته، الاغها راجستجو نما.»"},{"v":4,"t":"پس از کوهستان افرایم گذشته، واز زمین شلیشه عبور نموده، آنها را نیافتند. و اززمین شعلیم گذشتند و نبود و از زمین بنیامین گذشته، آنها را نیافتند."},{"v":5,"t":"و چون به زمین صوف رسیدند، شاول به خادمی که همراهش بود، گفت: «بیا برگردیم مباداپدرم از فکر الاغها گذشته، به فکر ما افتد.»"},{"v":6,"t":"او درجواب وی گفت: «اینک مرد خدایی در این شهراست و او مردی مکرم است و هر‌چه می‌گویدالبته واقع می‌شود. الان آنجا برویم؛ شاید از راهی که باید برویم ما را اطلاع بدهد.»"},{"v":7,"t":"شاول به خادمش گفت: «اینک اگر برویم چه چیز برای آن مرد ببریم، زیرا نان از ظروف ما تمام شده، وهدیه‌ای نیست که به آن مرد خدا بدهیم. پس چه چیز داریم.»"},{"v":8,"t":"و آن خادم باز در جواب شاول گفت که «اینک در دستم ربع مثقال نقره است. آن را به مرد خدا می‌دهم تا راه ما را به ما نشان دهد.»"},{"v":9,"t":"در زمان سابق چون کسی در اسرائیل برای درخواست کردن از خدا می‌رفت، چنین می‌گفت: «بیایید تا نزد رائی برویم.» زیرا نبی امروز را سابق رائی می‌گفتند."},{"v":10,"t":"و شاول به خادم خود گفت: «سخن تو نیکوست. بیا برویم.» پس به شهری که مرد خدا در آن بود، رفتند."},{"v":11,"t":"و چون ایشان به فراز شهر بالا می‌رفتند، دختران چند یافتند که برای آب کشیدن بیرون می‌آمدند و به ایشان گفتند: «آیا رائی دراینجاست؟»"},{"v":12,"t":"در جواب ایشان گفتند: «بلی اینک پیش روی شماست. حال بشتابید زیراامروز به شهر آمده است چونکه امروز قوم را درمکان بلند قربانی هست."},{"v":13,"t":"به مجرد ورود شما به شهر، قبل از آنکه به مکان بلند برای خوردن بیایید، به او خواهید برخورد زیرا که تا او نیایدقوم غذا نخواهند خورد، چونکه او می‌باید اول قربانی را برکت دهد و بعد از آن دعوت‌شدگان بخورند. پس اینک بروید زیرا که الان او راخواهید یافت.»"},{"v":14,"t":"پس به شهر رفتند و چون داخل شهر می‌شدند، اینک سموئیل به مقابل ایشان بیرون آمد تا به مکان بلند برود."},{"v":15,"t":"و یک روز قبل از آمدن شاول خداوند برسموئیل کشف نموده، گفت:"},{"v":16,"t":"«فردا مثل این وقت شخصی را از زمین بنیامین نزد تو می‌فرستم، او را مسح نما تا بر قوم من اسرائیل رئیس باشد، وقوم مرا از دست فلسطینیان رهایی دهد. زیرا که برقوم خود نظر کردم چونکه تضرع ایشان نزد من رسید.»"},{"v":17,"t":"و چون سموئیل شاول را دید، خداوند او را گفت: «اینک این است شخصی که درباره‌اش به تو گفتم که بر قوم من حکومت خواهد نمود.»"},{"v":18,"t":"و شاول در میان دروازه به سموئیل نزدیک آمده، گفت: «مرا بگو که خانه رائی کجاست؟»"},{"v":19,"t":"سموئیل در جواب شاول گفت: «من رائی هستم. پیش من به مکان بلند برو زیرا که شماامروز با من خواهید خورد، و بامدادان تو را رهاکرده، هرچه در دل خود داری برای تو بیان خواهم کرد."},{"v":20,"t":"و اما الاغهایت که سه روز قبل ازاین گم شده است، درباره آنها فکر مکن زیرا پیداشده است، و آرزوی تمامی اسرائیل بر کیست؟ آیا بر تو و بر تمامی خاندان پدر تو نیست؟»"},{"v":21,"t":"شاول در جواب گفت: «آیا من بنیامینی و ازکوچک ترین اسباط بنی‌اسرائیل نیستم؟ و آیاقبیله من از جمیع قبایل سبط بنیامین کوچکترنیست؟ پس چرا مثل این سخنان به من می‌گویی؟»"},{"v":22,"t":"و سموئیل شاول و خادمش را گرفته، ایشان را به مهمانخانه آورد و بر صدردعوت‌شدگان که قریب به سی نفر بودند، جا داد."},{"v":23,"t":"و سموئیل به طباخ گفت: «قسمتی را که به تودادم و درباره‌اش به تو گفتم که پیش خودنگاهدار، بیاور.»"},{"v":24,"t":"پس طباخ ران را با هرچه برآن بود، گرفته، پیش شاول گذاشت و سموئیل گفت: «اینک آنچه نگاهداشته شده است، پیش خود بگذار و بخور زیرا که تا زمان معین برای تونگاه داشته شده است، از وقتی که گفتم از قوم وعده بخواهم.»"},{"v":25,"t":"وچون ایشان از مکان بلند به شهر آمدند، او با شاول بر پشت بام گفتگو کرد."},{"v":26,"t":"و صبح زود برخاستندو نزد طلوع فجر سموئیل شاول را بر پشت بام خوانده، گفت: «برخیز تا تو را روانه نمایم.» پس شاول برخاست و هر دوی ایشان، او و سموئیل بیرون رفتند."},{"v":27,"t":"و چون ایشان به کنار شهر رسیدند، سموئیل به شاول گفت: «خادم را بگو که پیش مابرود. (و او پیش رفت ) و اما تو الان بایست تا کلام خدا را به تو بشنوانم.»"}]},"10":{"fa":[{"v":1,"t":"پس سموئیل ظرف روغن را گرفته، برسر وی ریخت و او را بوسیده، گفت: «آیا این نیست که خداوند تو را مسح کرد تا برمیراث او حاکم شوی؟"},{"v":2,"t":"امروز بعد از رفتنت ازنزد من دو مرد، نزد قبر راحیل به‌سرحد بنیامین درصلصح خواهی یافت، و تو را خواهند گفت: الاغهایی که برای جستن آنها رفته بودی، پیداشده است و اینک پدرت فکر الاغها را ترک کرده، به فکر شما افتاده است، و می‌گوید به جهت پسرم چکنم."},{"v":3,"t":"چون از آنجا پیش رفتی و نزد بلوط تابوررسیدی در آنجا سه مرد خواهی یافت که به حضور خدا به بیت ئیل می‌روند که یکی از آنها سه بزغاله دارد، و دیگری سه قرص نان، و سومی یک مشگ شراب."},{"v":4,"t":"و سلامتی تو را خواهند پرسید ودو نان به تو خواهندداد که از دست ایشان خواهی گرفت."},{"v":5,"t":"بعد از آن به جبعه خدا که در آنجا قراول فلسطینیان است خواهی آمد، و چون در آنجانزدیک شهر برسی گروهی از انبیا که از مکان بلندبه زیر می‌آیند و در‌پیش ایشان چنگ و دف و نای و بربط بوده، نبوت می‌کنند، به تو خواهندبرخورد."},{"v":6,"t":"و روح خداوند بر تو مستولی شده، باایشان نبوت خواهی نمود، و به مرد دیگر متبدل خواهی شد."},{"v":7,"t":"و هنگامی که این علامات به تورونماید، هرچه دستت یابد بکن زیرا خدا باتوست."},{"v":8,"t":"و پیش من به جلجال برو و اینک من برای گذرانیدن قربانی های سوختنی و ذبح نمودن ذبایح سلامتی نزد تو می‌آیم، و هفت روز منتظرباش تا نزد تو بیایم و تو را اعلام نمایم که چه بایدکرد.»"},{"v":9,"t":"و چون رو گردانید تا از نزد سموئیل برود، خدا او را قلب دیگر داد. و در آن روز جمیع این علامات واقع شد."},{"v":10,"t":"و چون آنجا به جبعه رسیدند، اینک گروهی از انبیا به وی برخوردند، وروح خدا بر او مستولی شده، در میان ایشان نبوت می‌کرد."},{"v":11,"t":"و چون همه کسانی که او را پیشترمی شناختند، دیدند که اینک با انبیا نبوت می‌کند، مردم به یکدیگر گفتند: «این چیست که با پسرقیس واقع شده است، آیا شاول نیز از‌جمله انبیااست؟»"},{"v":12,"t":"و یکی از حاضرین در جواب گفت: «اما پدر ایشان کیست؟» از این جهت مثل شد که آیا شاول نیز از‌جمله انبیا است."},{"v":13,"t":"و چون ازنبوت کردن فارغ شد به مکان بلند آمد."},{"v":14,"t":"و عموی شاول به او و به خادمش گفت: «کجا رفته بودید؟» او در جواب گفت: «برای جستن الاغها و چون دیدیم که نیستند، نزدسموئیل رفتیم.»"},{"v":15,"t":"عموی شاول گفت: «مرا بگوکه سموئیل به شما چه گفت؟»"},{"v":16,"t":"شاول به عموی خود گفت: «ما را واضح خبر داد که الاغها پیداشده است.» لیکن درباره امر سلطنت که سموئیل به او گفته بود، او را مخبر نساخت."},{"v":17,"t":"و سموئیل قوم را در مصفه به حضورخداوند خواند"},{"v":18,"t":"و به بنی‌اسرائیل گفت: «یهوه، خدای اسرائیل، چنین می‌گوید: من اسرائیل را ازمصر برآوردم، و شما از دست مصریان و از دست جمیع ممالکی که بر شما ظلم نمودند، رهایی دادم."},{"v":19,"t":"و شما امروز خدای خود را که شما را ازتمامی بدیها و مصیبت های شما رهانید، اهانت کرده، او را گفتید: پادشاهی بر ما نصب نما، پس الان با اسباط و هزاره های خود به حضور خداوندحاضر شوید.»"},{"v":20,"t":"و چون سموئیل جمیع اسباط اسرائیل راحاضر کرد، سبط بنیامین گرفته شد."},{"v":21,"t":"و سبطبنیامین را با قبایل ایشان نزدیک آورد، و قبیله مطری گرفته شد. و شاول پسر قیس گرفته شد، وچون او را طلبیدند، نیافتند."},{"v":22,"t":"پس بار دیگر ازخداوند سوال کردند که آیا آن مرد به اینجا دیگرخواهد آمد؟ خداوند در جواب گفت: «اینک اوخود را در میان اسبابها پنهان کرده است.»"},{"v":23,"t":"ودویده، او را از آنجا آوردند، و چون در میان قوم بایستاد، از تمامی قوم از کتف به بالا بلندتر بود."},{"v":24,"t":"و سموئیل به تمامی قوم گفت: «آیا شخصی راکه خداوند برگزیده است ملاحظه نمودید که درتمامی قوم مثل او کسی نیست؟» و تمامی قوم صدا زده، گفتند: «پادشاه زنده بماند!»"},{"v":25,"t":"پس سموئیل رسوم سلطنت را به قوم بیان کرده، در کتاب نوشت، و آن را به حضور خداوندگذاشت. و سموئیل هرکس از تمامی قوم را به خانه‌اش روانه نمود."},{"v":26,"t":"و شاول نیز به خانه خودبه جبعه رفت و فوجی از کسانی که خدا دل ایشان را برانگیخت همراه وی رفتند."},{"v":27,"t":"اما بعضی پسران بلیعال گفتند: «این شخص چگونه ما رابرهاند؟» و او را حقیر شمرده، هدیه برایش نیاوردند. اما او هیچ نگفت."}]},"11":{"fa":[{"v":1,"t":"و ناحاش عمونی برآمده، در برابر یابیش جلعاد اردو زد، و جمیع اهل یابیش به ناحاش گفتند: «با ما عهد ببند و تو را بندگی خواهیم نمود.»"},{"v":2,"t":"ناحاش عمونی به ایشان گفت: «به این شرط با شما عهد خواهم بست که چشمان راست جمیع شما کنده شود، و این را بر تمامی اسرائیل عار خواهم ساخت.»"},{"v":3,"t":"و مشایخ یابیش به وی گفتند: «ما را هفت روز مهلت بده تا رسولان به تمامی حدود اسرائیل بفرستیم، و اگر برای مارهاننده‌ای نباشد نزد تو بیرون خواهیم آمد.»"},{"v":4,"t":"پس رسولان به جبعه شاول آمده، این سخنان رابه گوش قوم رسانیدند، و تمامی قوم آواز خود رابلند کرده، گریستند."},{"v":5,"t":"و اینک شاول در عقب گاوان از صحرامی آمد، و شاول گفت: «قوم را چه شده است که می‌گریند؟» پس سخنان مردان یابیش را به او بازگفتند."},{"v":6,"t":"و چون شاول این سخنان را شنید روح خدا بر وی مستولی گشته، خشمش به شدت افروخته شد."},{"v":7,"t":"پس یک جفت گاو را گرفته، آنهارا پاره پاره نمود و به‌دست قاصدان به تمامی حدود اسرائیل فرستاده، گفت: «هر‌که در عقب شاول و سموئیل بیرون نیاید، به گاوان او چنین کرده شود.» آنگاه ترس خداوند بر قوم افتاد که مثل مرد واحد بیرون آمدند."},{"v":8,"t":"و ایشان را در بازق شمرد و بنی‌اسرائیل سیصد هزار نفر و مردان یهودا سی هزار بودند."},{"v":9,"t":"پس به رسولانی که آمده بودند گفتند: «به مردمان یابیش جلعاد چنین گویید: فردا وقتی که آفتاب گرم شود برای شماخلاصی خواهد شد.» و رسولان آمده، به اهل یابیش خبر دادند، پس ایشان شاد شدند."},{"v":10,"t":"ومردان یابیش گفتند: «فردا نزد شما بیرون خواهیم آمد تا هرچه در نظرتان پسند آید به ما بکنید.»"},{"v":11,"t":"و در فردای آن روز شاول قوم را به سه فرقه تقسیم نمود و ایشان در پاس صبح به میان لشکرگاه آمده، عمونیان را تا گرم شدن آفتاب می‌زدند، و باقی ماندگان پراکنده شدند به حدی که دو نفر از ایشان در یک جا نماندند."},{"v":12,"t":"و قوم به سموئیل گفتند: «کیست که گفته است! آیا شاول بر ما سلطنت نماید؟ آن کسان رابیاورید تا ایشان را بکشیم.»"},{"v":13,"t":"اما شاول گفت: «کسی‌امروز کشته نخواهد شد زیرا که خداوندامروز در اسرائیل نجات به عمل آورده است.»"},{"v":14,"t":"و سموئیل به قوم گفت: «بیایید تا به جلجال برویم و سلطنت را در آنجا از سر نو برقرار کنیم.»"},{"v":15,"t":"پس تمامی قوم به جلجال رفتند، و آنجا درجلجال، شاول را به حضور خداوند پادشاه ساختند، و در آنجا ذبایح سلامتی به حضورخداوند ذبح نموده، شاول و تمامی مردمان اسرائیل در آنجا شادی عظیم نمودند."}]},"12":{"fa":[{"v":1,"t":"و سموئیل به تمامی بنی‌اسرائیل گفت: «اینک قول شما را در هرآنچه به من گفتید، شنیدم و پادشاهی بر شما نصب نمودم."},{"v":2,"t":"وحال اینک پادشاه پیش روی شما راه می‌رود و من پیر و مو سفید شده‌ام، و اینک پسران من با شمامی باشند، و من از جوانیم تا امروز پیش روی شماسلوک نموده‌ام."},{"v":3,"t":"اینک من حاضرم، پس به حضور خداوند و مسیح او بر من شهادت دهید که گاو که را گرفتم؟ و الاغ که را گرفتم و بر که ظلم نموده، که را ستم کردم و از دست که رشوه گرفتم تا چشمان خود را به آن کور سازم و آن را به شمارد نمایم.»"},{"v":4,"t":"گفتند: «بر ما ظلم نکرده‌ای و بر ما ستم ننموده‌ای و چیزی از دست کسی نگرفته‌ای.»"},{"v":5,"t":"به ایشان گفت: «خداوند بر شماشاهد است و مسیح او امروز شاهد است که چیزی در دست من نیافته‌اید.» گفتند: «او شاهداست.»"},{"v":6,"t":"و سموئیل به قوم گفت: «خداوند است که موسی و هارون را مقیم ساخت و پدران شما را اززمین مصر برآورد."},{"v":7,"t":"پس الان حاضر شوید تا به حضور خداوند با شما درباره همه اعمال عادله خداوند که با شما و با پدران شما عمل نمود، محاجه نمایم."},{"v":8,"t":"چون یعقوب به مصر آمد وپدران شما نزد خداوند استغاثه نمودند، خداوندموسی و هارون را فرستاد که پدران شما را از مصربیرون آورده، ایشان را در این مکان ساکن گردانیدند."},{"v":9,"t":"و چون یهوه خدای خود را فراموش کردند ایشان را به‌دست سیسرا، سردار لشکرحاصور، و به‌دست فلسطینیان و به‌دست پادشاه موآب فروخت که با آنها جنگ کردند."},{"v":10,"t":"پس نزدخداوند فریاد برآورده، گفتند: «گناه کرده‌ایم زیراخداوند را ترک کرده بعلیم و عشتاروت را عبادت نموده‌ایم، و حال ما را از دست دشمنان ما رهایی ده و تو را عبادت خواهیم نمود."},{"v":11,"t":"پس خداوندیربعل و بدان و یفتاح و سموئیل را فرستاده، شمارا از دست دشمنان شما که در اطراف شما بودند، رهانید و در اطمینان ساکن شدید."},{"v":12,"t":"و چون دیدید که ناحاش، پادشاه بنی عمون، بر شمامی آید به من گفتید: نی بلکه پادشاهی بر ماسلطنت نماید، و حال آنکه یهوه، خدای شما، پادشاه شما بود."},{"v":13,"t":"و الان اینک پادشاهی که برگزیدید و او را طلبیدید. و همانا خداوند بر شماپادشاهی نصب نموده است."},{"v":14,"t":"اگر از خداوندترسیده، او را عبادت نمایید و قول او را بشنوید واز فرمان خداوند عصیان نورزید، و هم شما و هم پادشاهی که بر شما سلطنت می‌کند، یهوه، خدای خود را پیروی نمایید خوب."},{"v":15,"t":"و اما اگر قول خداوند را نشنوید و از فرمان خداوند عصیان ورزید، آنگاه دست خداوند چنانکه به ضد پدران شما بود، به ضد شما نیز خواهدبود."},{"v":16,"t":"پس الان بایستید و این کار عظیم را که خداوند به نظر شمابجا می‌آورد، ببینید."},{"v":17,"t":"آیا امروز وقت درو گندم نیست؟ از خداوند استدعا خواهم نمود و اورعدها و باران خواهد فرستاد تا بدانید و ببینید که شرارتی که از طلبیدن پادشاه برای خود نمودیددر نظر خداوند عظیم است.»"},{"v":18,"t":"پس سموئیل ازخداوند استدعا نمود و خداوند در همان روزرعدها و باران فرستاد، و تمامی قوم از خداوند وسموئیل بسیار ترسیدند."},{"v":19,"t":"و تمامی قوم به سموئیل گفتند: «برای بندگانت از یهوه، خدای خود استدعا نما تانمیریم، زیرا که بر تمامی گناهان خود این بدی راافزودیم که برای خود پادشاهی طلبیدیم.»"},{"v":20,"t":"وسموئیل به قوم گفت: «مترسید! شما تمامی این بدی را کرده‌اید، لیکن از پیروی خداوندبرنگردید، بلکه خداوند را به تمامی دل خودعبادت نمایید."},{"v":21,"t":"و در عقب اباطیلی که منفعت ندارد و رهایی نتواند داد، چونکه باطل است، برنگردید."},{"v":22,"t":"زیرا خداوند به‌خاطر نام عظیم خود قوم خود را ترک نخواهد نمود، چونکه خداوند را پسند آمد که شما را برای خود قومی سازد."},{"v":23,"t":"و اما من، حاشا از من که به خداوند گناه ورزیده، ترک دعا کردن برای شما نمایم، بلکه راه نیکو و راست را به شما تعلیم خواهم داد."},{"v":24,"t":"لیکن از خداوند بترسید و او را به راستی به تمامی دل خود عبادت نمایید و در کارهای عظیمی که برای شما کرده است، تفکر کنید."},{"v":25,"t":"و اما اگر شرارت ورزید، هم شما و هم پادشاه شما، هلاک خواهیدشد.»"}]},"13":{"fa":[{"v":1,"t":"و شاول (سی ) ساله بود که پادشاه شد. و چون دو سال بر اسرائیل سلطنت نموده بود،"},{"v":2,"t":"شاول به جهت خود سه هزار نفر ازاسرائیل برگزید، و از ایشان دو هزار با شاول درمخماس و در کوه بیت ئیل بودند، و یک هزار بایوناتان در جبعه بنیامین. و اما هرکس از بقیه قوم رابه خیمه‌اش فرستاد."},{"v":3,"t":"و یوناتان قراول فلسطینیان را که در جبعه بودند، شکست داد. و فلسطینیان این را شنیدند. و شاول در تمامی زمین کرنانواخته، گفت که «ای عبرانیان بشنوید!»"},{"v":4,"t":"و چون تمامی اسرائیل شنیدند که شاول قراول فلسطینیان را شکست داده است، و اینکه اسرائیل نزد فلسطینیان مکروه شده‌اند، قوم نزد شاول درجلجال جمع شدند."},{"v":5,"t":"و فلسطینیان سی هزار ارابه و شش هزارسوار و خلقی را که مثل ریگ کناره دریا بیشماربودند، جمع کردند تا با اسرائیل جنگ نمایند، وبرآمده، در مخماس به طرف شرقی بیت آون اردوزدند."},{"v":6,"t":"و چون اسرائیلیان را دیدند که در تنگی هستند زیرا که قوم مضطرب بودند، پس ایشان خود را در مغاره‌ها و بیشه‌ها و گریوه‌ها و حفره هاو صخره‌ها پنهان کردند."},{"v":7,"t":"و بعضی از عبرانیان ازاردن به زمین جاد و جلعاد عبور کردند. و شاول هنوز در جلجال بود و تمامی قوم در عقب او لرزان بودند."},{"v":8,"t":"پس هفت روز موافق وقتی که سموئیل تعیین نموده بود، درنگ کرد. اما سموئیل به جلجال نیامد و قوم از او پراکنده می‌شدند."},{"v":9,"t":"وشاول گفت: «قربانی سوختنی و ذبایح سلامتی رانزد من بیاورید.» و قربانی سوختنی را گذرانید."},{"v":10,"t":"و چون از گذرانیدن قربانی سوختنی فارغ شد، اینک سموئیل برسید و شاول به جهت تحیتش، به استقبال وی بیرون آمد."},{"v":11,"t":"و سموئیل گفت: «چه کردی؟» شاول گفت: «چون دیدم که قوم ازنزد من پراکنده می‌شوند و تو در روزهای معین نیامدی و فلسطینیان در مخماس جمع شده‌اند،"},{"v":12,"t":"پس گفتم: الان فلسطینیان بر من در جلجال فرود خواهند آمد، و من رضامندی خداوند رانطلبیدم. پس خویشتن را مجبور ساخته، قربانی سوختنی را گذرانیدم.»"},{"v":13,"t":"و سموئیل به شاول گفت: «احمقانه عمل نمودی و امری که یهوه خدایت به تو امر فرموده است، بجا نیاوردی، زیرا که حال خداوندسلطنت تو را بر اسرائیل تا به ابد برقرار می‌داشت."},{"v":14,"t":"لیکن الان سلطنت تو استوار نخواهد ماند وخداوند به جهت خویش مردی موافق دل خودطلب نموده است، و خداوند او را مامور کرده است که پیشوای قوم وی باشد، چونکه تو فرمان خداوند را نگاه نداشتی.»"},{"v":15,"t":"و سموئیل برخاسته، از جلجال به جبعه بنیامین آمد."},{"v":16,"t":"و شاول و پسرش یوناتان و قومی که با ایشان حاضر بودند در جبعه بنیامین ماندند، و فلسطینیان در مخماس اردو زدند."},{"v":17,"t":"و تاراج کنندگان از اردوی فلسطینیان در سه فرقه بیرون آمدند که یک فرقه از ایشان به راه عفره به زمین شوعال توجه نمودند."},{"v":18,"t":"و فرقه دیگر به راه بیت حورون میل کردند. و فرقه سوم به راه حدی که مشرف بر دره صبوعیم به‌جانب بیابان است، توجه نمودند."},{"v":19,"t":"و در تمام زمین اسرائیل آهنگری یافت نمی شد، زیرا که فلسطینیان می‌گفتند: «مباداعبرانیان برای خود شمشیر یا نیزه بسازند.»"},{"v":20,"t":"وجمیع اسرائیلیان نزد فلسطینیان فرود می‌آمدند تاهر کس بیل و گاوآهن و تبر و داس خود را تیزکند."},{"v":21,"t":"اما به جهت بیل و گاوآهن و چنگال سه دندانه و تبر و برای تیز کردن آهن گاوران سوهان داشتند."},{"v":22,"t":"و در روز جنگ، شمشیر و نیزه دردست تمامی قومی که با شاول و یوناتان بودندیافت نشد، اما نزد شاول و پسرش یوناتان بود."},{"v":23,"t":"و قراول فلسطینیان به معبر مخماس بیرون آمدند."}]},"14":{"fa":[{"v":1,"t":"و روزی واقع شد که یوناتان پسر شاول به جوان سلاح دار خود گفت: «بیا تا به قراول فلسطینیان که به آن طرفند بگذریم.» اماپدر خود را خبر نداد."},{"v":2,"t":"و شاول در کناره جبعه زیر درخت اناری که در مغرون است، ساکن بود وقومی که همراهش بودند تخمین ششصد نفربودند."},{"v":3,"t":"و اخیا ابن اخیطوب برادر ایخابودبن فینحاس بن عیلی، کاهن خداوند، در شیلوه باایفود ملبس شده بود، و قوم از رفتن یوناتان خبرنداشتند."},{"v":4,"t":"و در میان معبرهایی که یوناتان می خواست از آنها نزد قراول فلسطینیان بگذرد، یک صخره تیز به این طرف و یک صخره تیز به آن طرف بود، که اسم یکی بوصیص و اسم دیگری سنه بود."},{"v":5,"t":"و یکی از این صخره‌ها به طرف شمال در برابر مخماس ایستاده بود، و دیگری به طرف جنوب در برابر جبعه."},{"v":6,"t":"و یوناتان به جوان سلاحدار خود گفت: «بیانزد قراول این نامختونان بگذریم شاید خداوندبرای ما عمل کند زیرا که خداوند را از رهانیدن باکثیر یا با قلیل مانعی نیست.»"},{"v":7,"t":"و سلاحدارش به وی گفت: «هر‌چه در دلت باشد، عمل نما. پیش برو؛ اینک من موافق رای تو با تو هستم.»"},{"v":8,"t":"ویوناتان گفت: «اینک ما به طرف این مردمان گذرنماییم و خود را به آنها ظاهر سازیم،"},{"v":9,"t":"اگر به ماچنین گویند: بایستید تا نزد شما برسیم، آنگاه درجای خود خواهیم ایستاد و نزد ایشان نخواهیم رفت."},{"v":10,"t":"اما اگر چنین گویند که نزد ما برآیید، آنگاه خواهیم رفت زیرا خداوند ایشان را به‌دست ما تسلیم نموده است و به جهت ما، این علامت خواهد بود.»"},{"v":11,"t":"پس هر دوی ایشان خویشتن را به قراول فلسطینیان ظاهر ساختند و فلسطینیان گفتند: «اینک عبرانیان از حفره هایی که خود را در آنهاپنهان ساخته‌اند، بیرون می‌آیند.»"},{"v":12,"t":"و قراولان، یوناتان و سلاحدارش را خطاب کرده، گفتند: «نزد ما برآیید تا چیزی به شما نشان دهیم.» ویوناتان به سلاحدار خود گفت که «در عقب من بیازیرا خداوند ایشان را به‌دست اسرائیل تسلیم نموده است.»"},{"v":13,"t":"و یوناتان به‌دست و پای خود نزد ایشان بالارفت و سلاحدارش در عقب وی، و ایشان پیش روی یوناتان افتادند و سلاحدارش در عقب او می کشت."},{"v":14,"t":"و این کشتار اول که یوناتان وسلاحدارش کردند به قدر بیست نفر بود در قریب نصف شیار یک جفت گاو زمین."},{"v":15,"t":"و در اردو وصحرا و تمامی قوم تزلزل در‌افتاد و قراولان وتاراج کنندگان نیز لرزان شدند و زمین متزلزل شد، پس تزلزل عظیمی واقع گردید."},{"v":16,"t":"و دیده بانان شاول در جبعه بنیامین نگاه کردند و اینک آن انبوه گداخته شده، به هر طرف پراکنده می‌شدند."},{"v":17,"t":"و شاول به قومی که همراهش بودند، گفت: «الان تفحص کنید و ببینیداز ما که بیرون رفته است؟» پس تفحص کردند که اینک یوناتان و سلاحدارش حاضر نبودند."},{"v":18,"t":"وشاول به اخیا گفت: «تابوت خدا را نزدیک بیاور.» زیرا تابوت خدا در آن وقت همراه بنی‌اسرائیل بود."},{"v":19,"t":"و واقع شد چون شاول با کاهن سخن می‌گفت که اغتشاش در اردوی فلسطینیان زیاده وزیاده می‌شد، و شاول به کاهن گفت: «دست خودرا نگاهدار.»"},{"v":20,"t":"و شاول و تمامی قومی که با وی بودندجمع شده، به جنگ آمدند، و اینک شمشیر هرکس به ضد رفیقش بود و قتال بسیار عظیمی بود."},{"v":21,"t":"و عبرانیانی که قبل از آن با فلسطینیان بودند وهمراه ایشان از اطراف به اردو آمده بودند، ایشان نیز نزد اسرائیلیانی که با شاول و یوناتان بودند، برگشتند."},{"v":22,"t":"و تمامی مردان اسرائیل نیز که خودرا در کوهستان افرایم پنهان کرده بودند چون شنیدند که فلسطینیان منهزم شده‌اند، ایشان را درجنگ تعاقب نمودند."},{"v":23,"t":"پس خداوند در آن روزاسرائیل را نجات داد و جنگ تا بیت آون رسید."},{"v":24,"t":"و مردان اسرائیل آن روز در تنگی بودندزیرا که شاول قوم را قسم داده، گفته بود: «تا من ازدشمنان خود انتقام نکشیده باشم ملعون باد کسی که تا شام طعام بخورد.» و تمامی قوم طعام نچشیدند."},{"v":25,"t":"و تمامی قوم به جنگلی رسیدند که در آنجا عسل بر روی زمین بود."},{"v":26,"t":"و چون قوم به جنگل داخل شدند، اینک عسل می‌چکید امااحدی دست خود را به دهانش نبرد زیرا قوم ازقسم ترسیدند."},{"v":27,"t":"لیکن یوناتان هنگامی که پدرش به قوم قسم می‌داد نشنیده بود، پس نوک عصایی را که در دست داشت دراز کرده، آن را به‌شان عسل فرو برد، و دست خود را به دهانش برده، چشمان او روشن گردید."},{"v":28,"t":"و شخصی از قوم به او توجه نموده، گفت: «پدرت قوم را قسم سخت داده، گفت: ملعون بادکسی‌که امروز طعام خورد.» و قوم بی‌تاب شده بودند."},{"v":29,"t":"و یوناتان گفت: «پدرم زمین را مضطرب ساخته است، الان ببینید که چشمانم چه قدرروشن شده است که اندکی از این عسل چشیده‌ام."},{"v":30,"t":"و چه قدر زیاده اگر امروز قوم از غارت دشمنان خود که یافته‌اند بی‌ممانعت می‌خوردند، آیا قتال فلسطینیان بسیار زیاده نمی شد؟»"},{"v":31,"t":"و در آن روز فلسطینیان را از مخماس تاایلون منهزم ساختند و قوم بسیار بی‌تاب شدند."},{"v":32,"t":"و قوم بر غنیمت حمله کرده، از گوسفندان وگاوان و گوساله‌ها گرفته، بر زمین کشتند و قوم آنهارا با خون خوردند."},{"v":33,"t":"و شاول را خبر داده، گفتند: «اینک قوم به خداوند گناه ورزیده، با خون می‌خورند.» گفت: «شما خیانت ورزیده‌اید امروزسنگی بزرگ نزد من بغلطانید.»"},{"v":34,"t":"و شاول گفت: «خود را در میان قوم منتشر ساخته، به ایشان بگویید: هر کس گاو خود و هر کس گوسفند خود را نزد من بیاورد و در اینجا ذبح نموده، بخورید وبه خدا گناه نورزیده، با خون مخورید.» و تمامی قوم در آن شب هر کس گاوش را با خود آورده، در آنجا ذبح کردند."},{"v":35,"t":"و شاول مذبحی برای خداوند بنا کرد و این مذبح اول بود که برای خداوند بنا نمود."},{"v":36,"t":"و شاول گفت: «امشب در عقب فلسطینیان برویم و آنها را تا روشنایی صبح غارت کرده، ازایشان احدی را باقی نگذاریم.» ایشان گفتند: «هرچه در نظرت پسند آید بکن.» و کاهن گفت: «دراینجا به خدا تقرب بجوییم.»"},{"v":37,"t":"و شاول از خداسوال نمود که آیا از عقب فلسطینیان برویم و آیاایشان را به‌دست اسرائیل خواهی داد، اما در آن روز او را جواب نداد."},{"v":38,"t":"آنگاه شاول گفت: «ای تمامی روسای قوم به اینجا نزدیک شوید و بدانیدو ببینید که امروز این گناه در چه چیز است."},{"v":39,"t":"زیرا قسم به حیات خداوند رهاننده اسرائیل که اگر در پسرم یوناتان هم باشد، البته خواهدمرد.» لیکن از تمامی قوم احدی به او جواب نداد."},{"v":40,"t":"پس به تمامی اسرائیل گفت: «شما به یک طرف باشید و من با پسر خود یوناتان به یک طرف باشیم.» و قوم به شاول گفتند: «هر‌چه در نظرت پسند آید، بکن.»"},{"v":41,"t":"و شاول به یهوه، خدای اسرائیل گفت: «قرعه‌ای راست بده.» پس یوناتان و شاول گرفته شدند و قوم رها گشتند."},{"v":42,"t":"و شاول گفت: «در میان من و پسرم یوناتان قرعه بیندازید.» و یوناتان گرفته شد."},{"v":43,"t":"و شاول به یوناتان گفت: «مرا خبر ده که چه کرده‌ای؟» و یوناتان به او خبر داده، گفت: «به نوک عصایی که در دست دارم اندکی عسل چشیدم واینک باید بمیرم؟»"},{"v":44,"t":"و شاول گفت: «خدا چنین بلکه زیاده از این بکند‌ای یوناتان! زیرا البته خواهی مرد.»"},{"v":45,"t":"اما قوم به شاول گفتند: «آیایوناتان که نجات عظیم را در اسرائیل کرده است، باید بمیرد؟ حاشا! قسم به حیات خداوند که مویی از سرش به زمین نخواهد افتاد زیرا که امروز با خدا عمل نموده است.» پس قوم یوناتان را خلاص نمودند که نمرد."},{"v":46,"t":"و شاول از تعاقب فلسطینیان باز آمد و فلسطینیان به‌جای خودرفتند."},{"v":47,"t":"و شاول عنان سلطنت اسرائیل را به‌دست گرفت و با جمیع دشمنان اطراف خود، یعنی باموآب و بنی عمون و ادوم و ملوک صوبه وفلسطینیان جنگ کرد و به هر طرف که توجه می‌نمود، غالب می‌شد."},{"v":48,"t":"و به دلیری عمل می‌نمود و عمالیقیان را شکست داده، اسرائیل رااز دست تاراج کنندگان ایشان رهانید."},{"v":49,"t":"و پسران شاول، یوناتان و یشوی و ملکیشوبودند. و اسمهای دخترانش این است: اسم نخست زاده‌اش میرب و اسم کوچک میکال."},{"v":50,"t":"واسم زن شاول اخینوعام، دختر اخیمعاص، بود واسم سردار لشکرش ابنیر بن نیر، عموی شاول بود."},{"v":51,"t":"و قیس پدر شاول بود و نیر پدر ابنیر و پسرابیئیل بود."},{"v":52,"t":"و در تمامی روزهای شاول با فلسطینیان جنگ سخت بود و هر صاحب قوت و صاحب شجاعت که شاول می‌دید، او را نزد خودمی آورد."}]},"15":{"fa":[{"v":1,"t":"و سموئیل به شاول گفت: «خداوند مرافرستاد که ترا مسح نمایم تا بر قوم اواسرائیل پادشاه شوی. پس الان آواز کلام خداوند را بشنو."},{"v":2,"t":"یهوه صبایوت چنین می‌گوید: آنچه عمالیق به اسرائیل کرد، بخاطر داشته‌ام که چگونه هنگامی که از مصر برمی آمد، با او در راه مقاومت کرد."},{"v":3,"t":"پس الان برو و عمالیق را شکست داده، جمیع مایملک ایشان را بالکل نابود ساز، وبر ایشان شفقت مفرما بلکه مرد و زن و طفل وشیرخواره و گاو و گوسفند و شتر و الاغ را بکش.»"},{"v":4,"t":"پس شاول قوم را طلبید و از ایشان دویست هزار پیاده و ده هزار مرد از یهودا در طلایم سان دید."},{"v":5,"t":"و شاول به شهر عمالیق آمده، در وادی کمین گذاشت."},{"v":6,"t":"و شاول به قینیان گفت: «بروید وبرگشته، از میان عمالقه دور شوید، مبادا شما را باایشان هلاک سازم و حال آنکه شما با همه بنی‌اسرائیل هنگامی که از مصر برآمدند، احسان نمودید.» پس قینیان از میان عمالقه دور شدند."},{"v":7,"t":"وشاول عمالقه را از حویله تا شور که در برابر مصراست، شکست داد."},{"v":8,"t":"و اجاج پادشاه عمالیق رازنده گرفت و تمامی خلق را به دم شمشیر، بالکل هلاک ساخت."},{"v":9,"t":"و اما شاول و قوم اجاج را وبهترین گوسفندان و گاوان و پرواریها و بره‌ها و هرچیز خوب را دریغ نموده، نخواستند آنها راهلاک سازند. لیکن هر چیز خوار و بیقیمت رابالکل نابود ساختند."},{"v":10,"t":"و کلام خداوند بر سموئیل نازل شده، گفت:"},{"v":11,"t":"«پشیمان شدم که شاول را پادشاه ساختم زیرا از پیروی من برگشته، کلام مرا بجا نیاورده است.» و سموئیل خشمناک شده، تمامی شب نزد خداوند فریاد برآورد."},{"v":12,"t":"و بامدادان سموئیل برخاست تا شاول را ملاقات نماید وسموئیل را خبر داده، گفتند که «شاول به کرمل آمد و اینک به جهت خویشتن ستونی نصب نمودو دور زده، گذشت و در جلجال فرود آمده است.»"},{"v":13,"t":"و چون سموئیل نزد شاول رسید شاول به او گفت: «برکت خداوند بر تو باد! من فرمان خداوند را بجا آوردم.»"},{"v":14,"t":"سموئیل گفت: «پس این صدای گوسفندان در گوش من و بانگ گاوان که من می‌شنوم چیست؟»"},{"v":15,"t":"شاول گفت: «اینها رااز عمالقه آورده‌اند زیرا قوم بهترین گوسفندان وگاوان را دریغ داشتند تا برای یهوه خدایت قربانی نمایند، و بقیه را بالکل هلاک ساختیم.»"},{"v":16,"t":"سموئیل به شاول گفت: «تامل نما تا آنچه خداوند دیشب به من گفت به تو بگویم.» او وی راگفت: «بگو.»"},{"v":17,"t":"و سموئیل گفت: «هنگامی که تو در نظرخود کوچک بودی، آیا رئیس اسباط اسرائیل نشدی و آیا خداوند تو را مسح نکرد تا براسرائیل پادشاه شوی؟"},{"v":18,"t":"و خداوند تو را به راهی فرستاده، گفت: این عمالقه گناهکار را بالکل هلاک ساز و با ایشان جنگ کن تا نابود شوند."},{"v":19,"t":"پس چرا قول خداوند را نشنیدی بلکه برغنیمت هجوم آورده، آنچه را که در نظر خداوندبد است عمل نمودی؟»"},{"v":20,"t":"شاول به سموئیل گفت: «قول خداوند را استماع نمودم و به راهی که خداوند مرا فرستاد، رفتم و اجاج، پادشاه عمالقه را آوردم و عمالقه را بالکل هلاک ساختم."},{"v":21,"t":"اما قوم از غنیمت، گوسفندان و گاوان، یعنی بهترین آنچه حرام شده بود، گرفتند تا برای یهوه خدایت در جلجال قربانی بگذرانند.»"},{"v":22,"t":"سموئیل گفت: «آیا خداوند به قربانی های سوختنی وذبایح خوشنود است یا به اطاعت فرمان خداوند؟ اینک اطاعت از قربانی‌ها و گوش گرفتن از پیه قوچها نیکوتر است."},{"v":23,"t":"زیرا که تمرد مثل گناه جادوگری است وگردن کشی مثل بت‌پرستی و ترافیم است. چونکه کلام خداوند را ترک کردی او نیز تو را از سلطنت رد نمود.»"},{"v":24,"t":"و شاول به سموئیل گفت: «گناه کردم زیرااز فرمان خداوند و سخن تو تجاوز نمودم چونکه از قوم ترسیده، قول ایشان را شنیدم."},{"v":25,"t":"پس حال تمنا اینکه گناه مرا عفو نمایی و با من برگردی تاخداوند را عبادت نمایم.»"},{"v":26,"t":"سموئیل به شاول گفت: «با تو برنمی گردم چونکه کلام خداوند راترک نموده‌ای. خداوند نیز تو را از پادشاه بودن براسرائیل رد نموده است.»"},{"v":27,"t":"و چون سموئیل برگشت تا روانه شود، اودامن جامه او را بگرفت که پاره شد."},{"v":28,"t":"و سموئیل وی را گفت: «امروز خداوند سلطنت اسرائیل رااز تو پاره کرده، آن را به همسایه ات که از تو بهتراست، داده است."},{"v":29,"t":"و نیز جلال اسرائیل دروغ نمی گوید، و تغییر به اراده خود نمی دهد زیرا اوانسان نیست که به اراده خود تغییر دهد.»"},{"v":30,"t":"گفت: «گناه کرده‌ام، حال تمنا اینکه مرا به حضورمشایخ قومم و به حضور اسرائیل محترم داری وهمراه من برگردی تا یهوه خدایت را عبادت نمایم.»"},{"v":31,"t":"پس سموئیل در عقب شاول برگشت، و شاول خداوند را عبادت نمود."},{"v":32,"t":"و سموئیل گفت: «اجاج پادشاه عمالیق رانزد من بیاورید.» و اجاج به خرمی نزد او آمد واجاج گفت: «به درستی که تلخی موت گذشته است.»"},{"v":33,"t":"و سموئیل گفت: «چنانکه شمشیر توزنان را بی‌اولاد کرده است، همچنین مادر تو ازمیان زنان، بی‌اولاد خواهد شد.» و سموئیل اجاج را به حضور خداوند در جلجال پاره پاره کرد."},{"v":34,"t":"و سموئیل به رامه رفت و شاول به خانه خود به جبعه شاول برآمد."},{"v":35,"t":"و سموئیل برای دیدن شاول تا روز وفاتش دیگر نیامد. اماسموئیل برای شاول ماتم می‌گرفت، و خداوندپشیمان شده بود که شاول را بر اسرائیل پادشاه ساخته بود."}]},"16":{"fa":[{"v":1,"t":"و خداوند به سموئیل گفت: «تا به کی توبرای شاول ماتم می‌گیری چونکه من اورا از سلطنت نمودن بر اسرائیل رد نمودم. پس حقه خود را از روغن پر کرده، بیا تا تو را نزد یسای بیت لحمی بفرستم، زیرا که از پسرانش پادشاهی برای خود تعیین نموده‌ام.»"},{"v":2,"t":"سموئیل گفت: «چگونه بروم. اگر شاول بشنود مرا خواهدکشت.» خداوند گفت: «گوساله‌ای همراه خود ببرو بگو که به جهت گذرانیدن قربانی برای خداوندآمده‌ام."},{"v":3,"t":"و یسا را به قربانی دعوت نما، و من تو رااعلام می‌نمایم که چه باید بکنی، و کسی را که به تو امر نمایم برای من مسح نما.»"},{"v":4,"t":"و سموئیل آنچه را که خداوند به او گفته بود بجا آورده، به بیت لحم آمد، و مشایخ شهر لرزان شده، به استقبال او آمدند، و گفتند: «آیا با سلامتی می‌آیی؟»"},{"v":5,"t":"گفت: «با سلامتی به جهت قربانی گذرانیدن برای خداوند آمده‌ام، پس خود را تقدیس نموده، همراه من به قربانی بیایید.» و اویسا و پسرانش را تقدیس نموده، ایشان را به قربانی دعوت نمود."},{"v":6,"t":"و واقع شد که چون آمدند بر الیاب نظرانداخته، گفت: «یقین مسیح خداوند به حضوروی است.»"},{"v":7,"t":"اما خداوند به سموئیل گفت: «به چهره‌اش و بلندی قامتش نظر منما زیرا او را ردکرده‌ام، چونکه خداوند مثل انسان نمی نگرد، زیرا که انسان به ظاهر می‌نگرد و خداوند به دل می‌نگرد.»"},{"v":8,"t":"و یسا ابیناداب را خوانده، او را ازحضور سموئیل گذرانید، و او گفت: «خداوند این را نیز برنگزیده است.»"},{"v":9,"t":"و یسا شماه را گذرانید واو گفت: «خداوند این را نیز برنگزیده است.»"},{"v":10,"t":"ویسا هفت پسر خود را از حضور سموئیل گذرانیدو سموئیل به یسا گفت: «خداوند اینها رابرنگزیده است.»"},{"v":11,"t":"و سموئیل به یسا گفت: «آیا پسرانت تمام شدند.» گفت: «کوچکتر هنوز باقی است و اینک او گله را می‌چراند.» و سموئیل به یسا گفت: «بفرست و او را بیاور، زیرا که تا او به اینجا نیایدنخواهیم نشست.»"},{"v":12,"t":"پس فرستاده، او را آورد، واو سرخ رو و نیکوچشم و خوش منظر بود. وخداوند گفت: «برخاسته، او را مسح کن زیرا که همین است.»"},{"v":13,"t":"پس سموئیل حقه روغن راگرفته، او را در میان برادرانش مسح نمود، و از آن روز به بعد روح خداوند بر داود مستولی شد، وسموئیل برخاسته، به رامه رفت."},{"v":14,"t":"و روح خداوند از شاول دور شد، و روح بداز جانب خداوند او را مضطرب می‌ساخت."},{"v":15,"t":"وبندگان شاول وی را گفتند: «اینک روح بد از جانب خدا تو را مضطرب می‌سازد."},{"v":16,"t":"پس آقای ما بندگان خود را که به حضورت هستند امرفرماید تا کسی را که بر بربط نواختن ماهر باشدبجویند، و چون روح بد از جانب خدا بر تو بیایدبه‌دست خود بنوازد، و تو را نیکو خواهد شد.»"},{"v":17,"t":"و شاول به بندگان خود گفت: «الان کسی را که به نواختن ماهر باشد برای من پیدا کرده، نزد من بیاورید.»"},{"v":18,"t":"و یکی از خادمانش در جواب وی گفت: «اینک پسر یسای بیت لحمی را دیدم که به نواختن ماهر و صاحب شجاعت و مرد جنگ آزموده و فصیح زبان و شخص نیکو صورت است و خداوند با وی می‌باشد.»"},{"v":19,"t":"پس شاول قاصدان نزد یسا فرستاده، گفت: «پسرت داود را که با گوسفندان است، نزد من بفرست.»"},{"v":20,"t":"آنگاه یسا یک بار الاغ از نان و یک مشگ شراب و یک بزغاله گرفته، به‌دست پسرخود داود نزد شاول فرستاد."},{"v":21,"t":"و داود نزد شاول آمده، به حضور وی ایستاد و او وی را بسیاردوست داشت و سلاحدار او شد."},{"v":22,"t":"و شاول نزدیسا فرستاده، گفت: «داود نزد من بماند زیرا که به نظرم پسند آمد.»"},{"v":23,"t":"و واقع می‌شد هنگامی که روح بد از جانب خدا بر شاول می‌آمد که داودبربط گرفته، به‌دست خود می‌نواخت، و شاول راراحت و صحت حاصل می‌شد و روح بد از اومی رفت."}]},"17":{"fa":[{"v":1,"t":"و فلسطینیان لشکر خود را برای جنگ جمع نموده، در سوکوه که در یهودیه است، جمع شدند، و در میان سوکوه و عزیقه درافس دمیم اردو زدند."},{"v":2,"t":"و شاول و مردان اسرائیل جمع شده، در دره ایلاه اردو زده، به مقابله فلسطینیان صف آرایی کردند."},{"v":3,"t":"و فلسطینیان برکوه از یک طرف ایستادند، و اسرائیلیان بر کوه به طرف دیگر ایستادند، و دره در میان ایشان بود."},{"v":4,"t":"و از اردوی فلسطینیان مرد مبارزی مسمی به جلیات که از شهر جت بود بیرون آمد، و قدش شش ذراع و یک وجب بود."},{"v":5,"t":"و بر سر خود، خودبرنجینی داشت و به زره فلسی ملبس بود، و وزن زره‌اش پنج هزار مثقال برنج بود."},{"v":6,"t":"و بر ساقهایش ساق بندهای برنجین و در میان کتفهایش مزراق برنجین بود."},{"v":7,"t":"و چوب نیزه‌اش مثل نوردجولاهگان و سرنیزه‌اش ششصد مثقال آهن بود، و سپردارش پیش او می‌رفت."},{"v":8,"t":"و او ایستاده، افواج اسرائیل را صدا زد و به ایشان گفت: «چرابیرون آمده، صف آرایی نمودید؟ آیا من فلسطینی نیستم و شما بندگان شاول؟ برای خودشخصی برگزینید تا نزد من درآید."},{"v":9,"t":"اگر او بتواندبا من جنگ کرده، مرا بکشد، ما بندگان شماخواهیم شد، و اگر من بر او غالب آمده، او رابکشم شما بندگان ما شده، ما را بندگی خواهیدنمود.»"},{"v":10,"t":"و فلسطینی گفت: «من امروز فوجهای اسرائیل را به ننگ می‌آورم، شخصی به من بدهیدتا با هم جنگ نماییم.»"},{"v":11,"t":"و چون شاول و جمیع اسرائیلیان این سخنان فلسطینی را شنیدندهراسان شده، بسیار بترسیدند."},{"v":12,"t":"و داود پسر آن مرد افراتی بیت لحم یهودابود که یسا نام داشت، و او را هشت پسر بود، و آن مرد در ایام شاول در میان مردمان پیر و سالخورده بود."},{"v":13,"t":"و سه پسر بزرگ یسا روانه شده، در عقب شاول به جنگ رفتند و اسم سه پسرش که به جنگ رفته بودند: نخست زاده‌اش الیاب و دومش ابیناداب و سوم شماه بود."},{"v":14,"t":"و داود کوچکتر بودو آن سه بزرگ در عقب شاول رفته بودند."},{"v":15,"t":"و داود از نزد شاول آمد و رفت می‌کرد تا گوسفندان پدر خود را در بیت لحم بچراند."},{"v":16,"t":"و آن فلسطینی صبح و شام می‌آمد و چهل روز خود راظاهر می‌ساخت."},{"v":17,"t":"و یسا به پسر خود داود گفت: «الان به جهت برادرانت یک ایفه از این غله برشته و این ده قرص نان را بگیر و به اردو نزد برادرانت بشتاب."},{"v":18,"t":"و این ده قطعه پنیر را برای سردار هزاره ایشان ببر و از سلامتی برادرانت بپرس و از ایشان نشانی‌ای بگیر.»"},{"v":19,"t":"و شاول و آنها و جمیع مردان اسرائیل دردره ایلاه بودند و با فلسطینیان جنگ می‌کردند."},{"v":20,"t":"پس داود بامدادان برخاسته، گله را به‌دست چوپان واگذاشت و برداشته، چنانکه یسا او را امرفرموده بود برفت، و به سنگر اردو رسید وقتی که لشکر به میدان بیرون رفته، برای جنگ نعره می‌زدند."},{"v":21,"t":"و اسرائیلیان و فلسطینیان لشکر به مقابل لشکر صف آرایی کردند."},{"v":22,"t":"و داود اسبابی را که داشت به‌دست نگاهبان اسباب سپرد و به سوی لشکر دویده، آمد و سلامتی برادران خودرا بپرسید."},{"v":23,"t":"و چون با ایشان گفتگو می‌کرد اینک آن مرد مبارز فلسطینی جتی که اسمش جلیات بود از لشکر فلسطینیان برآمده، مثل پیش سخن گفت و داود شنید."},{"v":24,"t":"و جمیع مردان اسرائیل چون آن مرد رادیدند، از حضورش فرار کرده، بسیار ترسیدند."},{"v":25,"t":"و مردان اسرائیل گفتند: «آیا این مرد را که برمی آید، دیدید؟ یقین برای به ننگ‌آوردن اسرائیل برمی آید و هر‌که او را بکشد، پادشاه اورا از مال فراوان دولتمند سازد، و دختر خود را به او دهد، و خانه پدرش را در اسرائیل آزاد خواهدساخت.»"},{"v":26,"t":"و داود کسانی را که نزد او ایستاده بودند خطاب کرده، گفت: «به شخصی که این فلسطینی را بکشد و این ننگ را از اسرائیل برداردچه خواهد شد؟ زیرا که این فلسطینی نامختون کیست که لشکرهای خدای حی را به ننگ‌آورد؟»"},{"v":27,"t":"و قوم او را به همین سخنان خطاب کرده، گفتند: «به شخصی که او را بکشد، چنین خواهد شد.»"},{"v":28,"t":"و چون با مردمان سخن می‌گفتند برادربزرگش الیاب شنید و خشم الیاب بر داودافروخته شده، گفت: «برای چه اینجا آمدی و آن گله قلیل را در بیابان نزد که گذاشتی؟ من تکبر وشرارت دل تو را می‌دانم زیرا برای دیدن جنگ آمده‌ای.»"},{"v":29,"t":"داود گفت: «الان چه کردم آیا سببی نیست؟»"},{"v":30,"t":"پس از وی به طرف دیگری روگردانیده، به همین طور گفت و مردمان او را مثل پیشتر جواب دادند."},{"v":31,"t":"و چون سخنانی که داود گفت، مسموع شد، شاول را مخبر ساختند و او وی را طلبید."},{"v":32,"t":"و داود به شاول گفت: «دل کسی به‌سبب اونیفتد. بنده ات می‌رود و با این فلسطینی جنگ می‌کند.»"},{"v":33,"t":"شاول به داود گفت: «تو نمی توانی به مقابل این فلسطینی بروی تا با وی جنگ نمایی زیرا که تو جوان هستی و او از جوانیش مردجنگی بوده است.»"},{"v":34,"t":"داود به شاول گفت: «بنده ات گله پدر خود را می‌چراند که شیر وخرسی آمده، بره‌ای از گله ربودند."},{"v":35,"t":"و من آن راتعاقب نموده، کشتم و از دهانش رهانیدم و چون به طرف من بلند شد، ریش او را گرفته، او را زدم وکشتم."},{"v":36,"t":"بنده ات هم شیر و هم خرس را کشت، واین فلسطینی نامختون مثل یکی از آنها خواهدبود، چونکه لشکرهای خدای حی را به تنگ آورده است."},{"v":37,"t":"و داود گفت: خداوند که مرا از چنگ شیر و از چنگ خرس رهانید، مرا از دست این فلسطینی خواهد رهانید.» و شاول به داودگفت: «برو و خداوند با تو باد.»"},{"v":38,"t":"و شاول لباس خود را به داود پوشانید وخود برنجینی بر سرش نهاد و زره‌ای به اوپوشانید."},{"v":39,"t":"و داود شمشیرش را بر لباس خودبست و می‌خواست که برود زیرا که آنها رانیازموده بود و داود به شاول گفت: «با اینهانمی توانم رفت چونکه نیازموده‌ام.» پس داود آنهارا از بر خود بیرون آورد."},{"v":40,"t":"و چوب دستی خودرا به‌دست گرفته، پنج سنگ مالیده، از نهر سواکرد، و آنها را در کیسه شبانی که داشت، یعنی درانبان خود گذاشت و فلاخنش را به‌دست گرفته، به آن فلسطینی نزدیک شد."},{"v":41,"t":"و آن فلسطینی همی آمد تا به داود نزدیک شد و مردی که سپرش را برمی داشت پیش رویش می‌آمد."},{"v":42,"t":"و فلسطینی نظر افکنده، داودرا دید و او را حقیر شمرد زیرا جوانی خوشرو ونیکومنظر بود."},{"v":43,"t":"و فلسطینی به داود گفت: «آیامن سگ هستم که با چوب دستی نزد من می‌آیی؟» و فلسطینی داود را به خدایان خود لعنت کرد."},{"v":44,"t":"و فلسطینی به داود گفت: «نزد من بیا تا گوشت تو را به مرغان هوا و درندگان صحرا بدهم.»"},{"v":45,"t":"داود به فلسطینی گفت: «تو با شمشیر و نیزه و مزراق نزد من می‌آیی اما من به اسم یهوه صبایوت، خدای لشکرهای اسرائیل که او را به ننگ‌آورده‌ای نزد تو می‌آیم."},{"v":46,"t":"و خداوند امروزتو را به‌دست من تسلیم خواهد کرد و تو را زده، سر تو را از تنت جدا خواهم کرد، و لاشه های لشکر فلسطینیان را امروز به مرغان هوا و درندگان زمین خواهم داد تا تمامی زمین بدانند که دراسرائیل خدایی هست."},{"v":47,"t":"و تمامی این جماعت خواهند دانست که خداوند به شمشیر و نیزه خلاصی نمی دهد زیرا که جنگ از آن خداونداست و او شما را به‌دست ما خواهد داد.»"},{"v":48,"t":"و چون فلسطینی برخاسته، پیش آمد و به مقابله داود نزدیک شد، داود شتافته، به مقابله فلسطینی به سوی لشکر دوید."},{"v":49,"t":"و داود دست خود را به کیسه‌اش برد و سنگی از آن گرفته، ازفلاخن انداخت و به پیشانی فلسطینی زد، و سنگ به پیشانی او فرو رفت که بر روی خود بر زمین افتاد."},{"v":50,"t":"پس داود بر فلسطینی با فلاخن و سنگ غالب آمده، فلسطینی را زد و کشت و در دست داود شمشیری نبود."},{"v":51,"t":"و داود دویده، بر آن فلسطینی‌ایستاد، و شمشیر او را گرفته، ازغلافش کشید و او را کشته، سرش را با آن از تنش جدا کرد، و چون فلسطینیان، مبارز خود را کشته دیدند، گریختند."},{"v":52,"t":"و مردان اسرائیل و یهودابرخاستند و نعره زده، فلسطینیان را تا جت و تادروازه های عقرون تعاقب نمودند و مجروحان فلسطینیان به راه شعریم تا به جت و عقرون افتادند."},{"v":53,"t":"و بنی‌اسرائیل از تعاقب نمودن فلسطینیان برگشتند و اردوی ایشان را غارت نمودند."},{"v":54,"t":"و داود سر فلسطینی را گرفته، به اورشلیم آورد اما اسلحه او را در خیمه خودگذاشت."},{"v":55,"t":"و چون شاول داود را دید که به مقابله فلسطینی بیرون می‌رود، به‌سردار لشکرش ابنیرگفت: «ای ابنیر، این جوان پسر کیست؟» ابنیر گفت: «ای پادشاه به‌جان تو قسم که نمی دانم.»"},{"v":56,"t":"پادشاه گفت: «بپرس که این جوان پسر کیست.»"},{"v":57,"t":"و چون داود از کشتن فلسطینی برگشت، ابنیراو را گرفته، به حضور شاول آورد، و سر آن فلسطینی در دستش بود."},{"v":58,"t":"و شاول وی را گفت: «ای جوان تو پسر کیستی؟» داود گفت: «پسربنده ات، یسای بیت لحمی، هستم.»"}]},"18":{"fa":[{"v":1,"t":"و واقع شد که چون از سخن‌گفتن باشاول فارغ شد، دل یوناتان بر دل داودچسبید، و یوناتان او را مثل جان خویش دوست داشت."},{"v":2,"t":"و در آن روز شاول وی را گرفته، نگذاشت که به خانه پدرش برگردد."},{"v":3,"t":"و یوناتان باداود عهد بست چونکه او را مثل جان خوددوست داشته بود."},{"v":4,"t":"و یوناتان ردایی را که دربرش بود، بیرون کرده، آن را به داود داد و رخت خود حتی شمشیر و کمان و کمربند خویش رانیز."},{"v":5,"t":"و داود به هر جایی که شاول او را می‌فرستادبیرون می‌رفت، و عاقلانه حرکت می‌کرد و شاول او را بر مردان جنگی خود گماشت، و به نظرتمامی قوم و به نظر خادمان شاول نیز مقبول افتاد."},{"v":6,"t":"و واقع شد هنگامی که داود از کشتن فلسطینی برمی گشت چون ایشان می‌آمدند که زنان از جمیع شهرهای اسرائیل با دفها و شادی وبا آلات موسیقی سرود و رقص‌کنان به استقبال شاول پادشاه بیرون آمدند."},{"v":7,"t":"و زنان لهو و لعب کرده، به یکدیگر می‌سراییدند و می‌گفتند: «شاول هزاران خود را و داود ده هزاران خود را کشته است.»"},{"v":8,"t":"و شاول بسیار غضبناک شد، و این سخن در نظرش ناپسند آمده، گفت: «به داود ده هزاران دادند و به من هزاران دادند، پس غیر از سلطنت برایش چه باقی است.»"},{"v":9,"t":"و از آن روز به بعد شاول بر داود به چشم بد می‌نگریست."},{"v":10,"t":"و در فردای آن روز روح بد از جانب خدا برشاول آمده، در میان خانه شوریده احوال گردید. و داود مثل هر روز به‌دست خود می‌نواخت ومزراقی در دست شاول بود."},{"v":11,"t":"و شاول مزراق راانداخته، گفت: داود را تا به دیوار خواهم زد، اماداود دو مرتبه از حضورش خویشتن را به کنارکشید."},{"v":12,"t":"و شاول از داود می‌ترسید زیرا خداوند با اوبود و از شاول دور شده."},{"v":13,"t":"پس شاول وی را ازنزد خود دور کرد و او را سردار هزاره خود نصب نمود، و به حضور قوم خروج و دخول می‌کرد."},{"v":14,"t":"و داود در همه رفتار خود عاقلانه حرکت می‌نمود، و خداوند با وی می‌بود."},{"v":15,"t":"و چون شاول دید که او بسیار عاقلانه حرکت می‌کند به‌سبب او هراسان می‌بود."},{"v":16,"t":"اما تمامی اسرائیل ویهودا داود را دوست می‌داشتند، زیرا که به حضور ایشان خروج و دخول می‌کرد."},{"v":17,"t":"و شاول به داود گفت: «اینک دختر بزرگ خود میرب را به تو به زنی می‌دهم. فقط برایم شجاع باش و در جنگهای خداوند بکوش، زیراشاول می‌گفت: «دست من بر او دراز نشود بلکه دست فلسطینیان.»"},{"v":18,"t":"و داود به شاول گفت: من کیستم و جان من و خاندان پدرم در اسرائیل چیست تا داماد پادشاه بشوم.»"},{"v":19,"t":"و در وقتی که میرب دختر شاول می‌بایست به داود داده شود اوبه عدریئیل محولاتی به زنی داده شد."},{"v":20,"t":"و میکال، دختر شاول، داود را دوست می‌داشت، و چون شاول را خبر دادند این امر وی را پسند آمد."},{"v":21,"t":"و شاول گفت: «او را به وی می‌دهم تا برایش دام شود و دست فلسطینیان براو دراز شود.» پس شاول به داود بار دوم گفت: «امروز داماد من خواهی شد.»"},{"v":22,"t":"و شاول خادمان خود را فرمود که در خفا با داود متکلم شده، بگویید: «اینک پادشاه از تو راضی است وخادمانش تو را دوست می‌دارند؛ پس الان دامادپادشاه بشو.»"},{"v":23,"t":"پس خادمان شاول این سخنان را به سمع داود رسانیدند و داود گفت: «آیا در نظر شما دامادپادشاه شدن آسان است؟ و حال آنکه من مردمسکین و حقیرم.»"},{"v":24,"t":"و خادمان شاول او را خبرداده، گفتند که داود به این طور سخن گفته است."},{"v":25,"t":"و شاول گفت: «به داود چنین بگویید که پادشاه مهر نمی خواهد جز صد قلفه فلسطینیان تا ازدشمنان پادشاه انتقام کشیده شود.» و شاول فکرکرد که داود را به‌دست فلسطینیان به قتل رساند."},{"v":26,"t":"پس خادمانش داود را از این امر خبر دادندو این سخن به نظر داود پسند آمد که داماد پادشاه بشود، و روزهای معین هنوز تمام نشده بود."},{"v":27,"t":"پس داود برخاسته، با مردان خود رفت ودویست نفر از فلسطینیان را کشته، داود قلفه های ایشان را آورد و آنها را تمام نزد پادشاه گذاشتند، تا داماد پادشاه بشود. و شاول دختر خود میکال رابه وی به زنی داد."},{"v":28,"t":"و شاول دید و فهمید که خداوند با داود است. و میکال دختر شاول او رادوست می‌داشت."},{"v":29,"t":"و شاول از داود باز بیشترترسید، و شاول همه اوقات دشمن داود بود."},{"v":30,"t":"و بعد از آن سرداران فلسطینیان بیرون آمدند، و هر دفعه که بیرون می‌آمدند داود از جمیع خادمان شاول زیاده عاقلانه حرکت می‌کرد، و از این جهت اسمش بسیار شهرت یافت."}]},"19":{"fa":[{"v":1,"t":"و شاول به پسر خود یوناتان و به جمیع خادمان خویش فرمود تا داود رابکشند."},{"v":2,"t":"اما یوناتان پسر شاول به داود بسیار میل داشت، و یوناتان داود را خبر داده، گفت: «پدرم شاول قصد قتل تو دارد، پس الان تا بامدادان خویشتن را نگاهدار و در جایی مخفی مانده، خود را پنهان کن."},{"v":3,"t":"و من بیرون آمده، به پهلوی پدرم در صحرایی که تو در آن می‌باشی خواهم ایستاد، و درباره تو با پدرم گفتگو خواهم کرد واگر چیزی ببینم تو را اطلاع خواهم داد.»"},{"v":4,"t":"و یوناتان درباره داود نزد پدر خود شاول به نیکویی سخن رانده، وی را گفت: «پادشاه بر بنده خود داود گناه نکند زیرا که او به تو گناه نکرده است بلکه اعمال وی برای تو بسیار نیکو بوده است."},{"v":5,"t":"و جان خویش را به‌دست خود نهاده، آن فلسطینی را کشت و خداوند نجات عظیمی به جهت تمامی اسرائیل نمود و تو آن را دیده، شادمان شدی؛ پس چرا به خون بی‌تقصیری گناه کرده، داود را بی‌سبب بکشی.»"},{"v":6,"t":"و شاول به سخن یوناتان گوش گرفت، و شاول قسم خورد که به حیات خداوند او کشته نخواهد شد."},{"v":7,"t":"آنگاه یوناتان داود را خواند و یوناتان او را از همه این سخنان خبر داد و یوناتان داود را نزد شاول آورده، او مثل ایام سابق در حضور وی می‌بود."},{"v":8,"t":"و باز جنگ واقع شده، داود بیرون رفت و بافلسطینیان جنگ کرده، ایشان را به کشتار عظیمی شکست داد و از حضور وی فرار کردند."},{"v":9,"t":"و روح بد از جانب خداوند بر شاول آمد و او در خانه خود نشسته، مزراق خویش را در دست داشت وداود به‌دست خود می‌نواخت."},{"v":10,"t":"و شاول خواست که داود را با مزراق خود تا به دیوار بزند، اما او از حضور شاول بگریخت و مزراق را به دیوار زد و داود فرار کرده، آن شب نجات یافت."},{"v":11,"t":"و شاول قاصدان به خانه داود فرستاد تا آن را نگاهبانی نمایند و در صبح او را بکشند. امامیکال، زن داود، او را خبر داده، گفت: «اگر امشب جان خود را خلاص نکنی، فردا کشته خواهی شد.»"},{"v":12,"t":"پس میکال داود را از پنجره فرو هشته، اوروانه شد و فرار کرده، نجات یافت."},{"v":13,"t":"اما میکال ترافیم را گرفته، آن را در بستر نهاد و بالینی از پشم بز زیر سرش نهاده، آن را با رخت پوشانید."},{"v":14,"t":"وچون شاول قاصدان فرستاده تا داود را بگیرند، گفت بیمار است."},{"v":15,"t":"پس شاول قاصدان را فرستادتا داود را ببینند و گفت: «او را بر بسترش نزد من بیاورید تا او را بکشم.»"},{"v":16,"t":"و چون قاصدان داخل شدند، اینک ترافیم در بستر و بالین پشم بز زیرسرش بود."},{"v":17,"t":"و شاول به میکال گفت: «برای چه مرا چنین فریب دادی و دشمنم را رها کردی تانجات یابد.» و میکال شاول را جواب داد که او به من گفت: «مرا رها کن؛ برای چه تو را بکشم؟»"},{"v":18,"t":"و داود فرار کرده، رهایی یافت و نزدسموئیل به رامه آمده، از هر‌آنچه شاول با وی کرده بود، او را مخبر ساخت، و او و سموئیل رفته، در نایوت ساکن شدند."},{"v":19,"t":"پس شاول را خبرداده، گفتند: «اینک داود در نایوت رامه است.»"},{"v":20,"t":"و شاول قاصدان برای گرفتن داود فرستاد، وچون جماعت انبیا را دیدند که نبوت می‌کنند و سموئیل را که به پیشوایی ایشان ایستاده است، روح خدا بر قاصدان شاول آمده، ایشان نیز نبوت کردند."},{"v":21,"t":"و چون شاول را خبر دادند قاصدان دیگر فرستاده، ایشان نیز نبوت کردند، و شاول بازقاصدان سوم فرستاده، ایشان نیز نبوت کردند."},{"v":22,"t":"پس خود او نیز به رامه رفت و چون به چاه بزرگ که نزد سیخوه است رسید، سوال کرده، گفت: «سموئیل و داود کجا می‌باشند؟» و کسی گفت: «اینک در نایوت رامه هستند.»"},{"v":23,"t":"و به آنجابه نایوت رامه روانه شد و روح خدا بر او نیز آمد ودر حینی که می‌رفت نبوت می‌کرد تا به نایوت رامه رسید."},{"v":24,"t":"و او نیز جامه خود را کنده، به حضور سموئیل نبوت می‌کرد و تمامی آن روز وتمامی آن شب برهنه افتاد، بنابراین گفتند: «آیاشاول نیز از‌جمله انبیاست؟»"}]},"20":{"fa":[{"v":1,"t":"و داود از نایوت رامه فرار کرده، آمد وبه حضور یوناتان گفت: «چه کرده‌ام وعصیانم چیست و در نظر پدرت چه گناهی کرده‌ام که قصد جان من دارد؟»"},{"v":2,"t":"او وی را گفت: «حاشا! تو نخواهی مرد. اینک پدر من امری بزرگ وکوچک نخواهد کرد جز آنکه مرا اطلاع خواهدداد. پس چگونه پدرم این امر را از من مخفی بدارد؟ چنین نیست.»"},{"v":3,"t":"و داود نیز قسم خورده، گفت: «پدرت نیکومی داند که در نظر تو التفات یافته‌ام، و می‌گویدمبادا یوناتان این را بداند و غمگین شود، و لکن به حیات خداوند و به حیات تو که در میان من وموت یک قدم بیش نیست.»"},{"v":4,"t":"یوناتان به داود گفت: «هر‌چه دلت بخواهد آن را برای تو خواهم نمود.»"},{"v":5,"t":"داود به یوناتان گفت: «اینک فردا اول ماه است و من می‌باید با پادشاه به غذا بنشینم، پس مرا رخصت بده که تا شام سوم، خود را در صحراپنهان کنم."},{"v":6,"t":"اگر پدرت مرا مفقود بیند بگو داود ازمن بسیار التماس نمود که به شهر خود به بیت لحم بشتابد، زیرا که تمامی قبیله او را آنجا قربانی سالیانه است."},{"v":7,"t":"اگر گوید که خوب، آنگاه بنده ات را سلامتی خواهد بود، و اما اگر بسیار غضبناک شود بدانکه او به بدی جازم شده است."},{"v":8,"t":"پس بابنده خود احسان نما چونکه بنده خویش را باخودت به عهد خداوند در‌آوردی و اگر عصیان در من باشد، خودت مرا بکش زیرا برای چه مرانزد پدرت ببری.»"},{"v":9,"t":"یوناتان گفت: «حاشا از تو! زیرا اگرمی دانستم بدی از جانب پدرم جزم شده است که بر تو بیاید، آیا تو را از آن اطلاع نمی دادم؟»"},{"v":10,"t":"داود به یوناتان گفت: «اگر پدرت تو را به درشتی جواب دهد کیست که مرا مخبر سازد؟»"},{"v":11,"t":"یوناتان به داود گفت: «بیا تا به صحرا برویم.» وهر دوی ایشان به صحرا رفتند."},{"v":12,"t":"و یوناتان به داود گفت: «ای یهوه، خدای اسرائیل، چون فردا یا روز سوم پدر خود را مثل این وقت آزمودم و اینک اگر برای داود خیر باشد، اگر من نزد او نفرستم و وی را اطلاع ندهم،"},{"v":13,"t":"خداوند به یوناتان مثل این بلکه زیاده از این عمل نماید، و اما اگر پدرم ضرر تو را صواب بیند، پس تو را اطلاع داده، رها خواهم نمود تا به سلامتی بروی و خداوند همراه تو باشد چنانکه همراه پدر من بود."},{"v":14,"t":"و نه‌تنها مادام حیاتم، لطف خداوند را با من بجا آوری تا نمیرم،"},{"v":15,"t":"بلکه لطف خود را از خاندانم تا به ابد قطع ننمایی، هم دروقتی که خداوند دشمنان داود را جمیع از روی زمین منقطع ساخته باشد.»"},{"v":16,"t":"پس یوناتان باخاندان داود عهد بست و گفت خداوند این را ازدشمنان داود مطالبه نماید."},{"v":17,"t":"و یوناتان بار دیگربه‌سبب محبتی که با او داشت داود را قسم دادزیرا که او را دوست می‌داشت چنانکه جان خودرا دوست می‌داشت."},{"v":18,"t":"و یوناتان او را گفت: «فردا اول ماه است وچونکه جای تو خالی می‌باشد، تو را مفقودخواهند یافت."},{"v":19,"t":"و در روز سوم به زودی فرودشده، به‌جایی که خود را در آن در روز شغل پنهان کردی بیا و در جانب سنگ آزل بنشین."},{"v":20,"t":"ومن سه تیر به طرف آن خواهم‌انداخت که گویا به هدف می‌اندازم."},{"v":21,"t":"و اینک خادم خود رافرستاده، خواهم گفت برو و تیرها را پیدا کن و اگربه خادم گویم: اینک تیرها از این طرف تو است. آنها را بگیر. آنگاه بیا زیرا که برای تو سلامتی است و به حیات خداوند تو را هیچ ضرری نخواهد بود."},{"v":22,"t":"اما اگر به خادم چنین بگویم که: اینک تیرها از آن طرف توست، آنگاه برو زیراخداوند تو را رها کرده است."},{"v":23,"t":"و اما آن کاری که من و تو درباره آن گفتگو کردیم اینک خداوند درمیان من و تو تا به ابد خواهد بود.»"},{"v":24,"t":"پس داود خود را در صحرا پنهان کرد و چون اول ماه رسید، پادشاه برای غذا خوردن نشست."},{"v":25,"t":"و پادشاه در جای خود بر‌حسب عادتش برمسند، نزد دیوار نشسته، و یوناتان ایستاده بود و ابنیر به پهلوی شاول نشسته، و جای داود خالی بود."},{"v":26,"t":"و شاول در آن روز هیچ نگفت زیرا گمان می‌برد: «چیزی بر او واقع شده، طاهر نیست. البته طاهر نیست!»"},{"v":27,"t":"و در فردای اول ماه که روز دوم بود، جای داود نیز خالی بود. پس شاول به پسرخود یوناتان گفت: «چرا پسر یسا، هم دیروز و هم امروز به غذا نیامد؟»"},{"v":28,"t":"یوناتان در جواب شاول گفت: «داود از من بسیار التماس نمود تا به بیت لحم برود."},{"v":29,"t":"و گفت: تمنا اینکه مرا رخصت بدهی زیرا خاندان ما را در شهر قربانی است وبرادرم مرا امر فرموده است، پس اگر الان در نظرتو التفات یافتم، مرخص بشوم تا برادران خودراببینم. از این جهت به سفره پادشاه نیامده است.»"},{"v":30,"t":"آنگاه خشم شاول بر یوناتان افروخته شده، او را گفت: «ای پسر زن کردنکش فتنه انگیز، آیانمی دانم که تو پسر یسا را به جهت افتضاح خود وافتضاح عورت مادرت اختیار کرده‌ای؟"},{"v":31,"t":"زیرامادامی که پسر یسا بر روی زمین زنده باشد تو وسلطنت تو پایدار نخواهید ماند. پس الان بفرست و او را نزد من بیاور زیرا که البته خواهد مرد.»"},{"v":32,"t":"یوناتان پدر خود شاول را جواب داده، وی راگفت: «چرا بمیرد؟ چه کرده است؟»"},{"v":33,"t":"آنگاه شاول مزراق خود را به او انداخت تااو را بزند. پس یوناتان دانست که پدرش بر کشتن داود جازم است."},{"v":34,"t":"و یوناتان به شدت خشم، ازسفره برخاست و در روز دوم ماه، طعام نخوردچونکه برای داود غمگین بود زیرا پدرش او راخجل ساخته بود."},{"v":35,"t":"و بامدادان یوناتان در وقتی که با داود تعیین کرده بود به صحرا بیرون رفت و یک پسر کوچک همراهش بود."},{"v":36,"t":"و به خادم خود گفت: «بدو وتیرها را که می‌اندازم پیدا کن.» و چون پسرمی دوید تیر را چنان انداخت که از او رد شد."},{"v":37,"t":"وچون پسر به مکان تیری که یوناتان انداخته بود، می‌رفت، یوناتان در عقب پسر آواز داده، گفت که: «آیا تیر به آن طرف تو نیست؟»"},{"v":38,"t":"و یوناتان درعقب پسر آواز داد که بشتاب و تعجیل کن ودرنگ منما. پس خادم یوناتان تیرها را برداشته، نزد آقای خود برگشت."},{"v":39,"t":"و پسر چیزی نفهمید. اما یوناتان و داود این امر را می‌دانستند."},{"v":40,"t":"ویوناتان اسلحه خود را به خادم خود داده، وی راگفت: «برو و آن را به شهر ببر.»"},{"v":41,"t":"و چون پسر رفته بود، داود از جانب جنوبی برخاست و بر روی خود بر زمین افتاده، سه مرتبه سجده کرد و یکدیگر را بوسیده، با هم گریه کردند تا داود از حد گذرانید."},{"v":42,"t":"و یوناتان به داودگفت: «به سلامتی برو چونکه ما هر دو به نام خداوند قسم خورده، گفتیم که خداوند در میان من و تو و در میان ذریه من و ذریه تو تا به ابد باشد. پس برخاسته، برفت و یوناتان به شهر برگشت."}]},"21":{"fa":[{"v":1,"t":"و داود به نوب نزد اخیملک کاهن رفت، و اخیملک لرزان شده، به استقبال داودآمده، گفت: «چرا تنها آمدی و کسی با تونیست؟»"},{"v":2,"t":"داود به اخیملک کاهن گفت: «پادشاه مرا به‌کاری مامور فرمود و مرا گفت: از این کاری که تو را می‌فرستم و از آنچه به تو امر فرمودم کسی اطلاع نیابد، و خادمان را به فلان و فلان جا تعیین نمودم."},{"v":3,"t":"پس الان چه در دست داری، پنج قرص نان یا هر‌چه حاضر است به من بده.»"},{"v":4,"t":"کاهن در جواب داود گفت: «هیچ نان عام دردست من نیست، لیکن نان مقدس هست اگرخصوص خادمان، خویشتن را از زنان بازداشته باشند.»"},{"v":5,"t":"داود در جواب کاهن گفت: «به درستی که در این سه روز زنان از ما دور بوده‌اند و چون بیرون آمدم ظروف جوانان مقدس بود، و آن بطوری عام است خصوص چونکه امروز دیگری در ظرف مقدس شده است.»"},{"v":6,"t":"پس کاهن، نان مقدس را به او داد زیرا که در آنجا نانی نبود غیر ازنان تقدمه که از حضور خداوند برداشته شده بود، تا در روز برداشتنش نان گرم بگذارند."},{"v":7,"t":"و در آن روز یکی از خادمان شاول که مسمی به دوآغ ادومی بود، به حضور خداوند اعتکاف داشت، و بزرگترین شبانان شاول بود."},{"v":8,"t":"و داود به اخیملک گفت: «آیا اینجا دردستت نیزه یا شمشیر نیست زیرا که شمشیر وسلاح خویش را با خود نیاورده‌ام چونکه کارپادشاه به تعجیل بود.»"},{"v":9,"t":"کاهن گفت: «اینک شمشیر جلیات فلسطینی که در دره ایلاه کشتی، در پشت ایفود به‌جامه ملفوف است. اگرمی خواهی آن را بگیری بگیر، زیرا غیر از آن دراینجا نیست.» داود گفت: «مثل آن، دیگری نیست. آن را به من بده.»"},{"v":10,"t":"پس داود آن روز برخاسته، از حضورشاول فرار کرده، نزد اخیش، ملک جت آمد."},{"v":11,"t":"و خادمان اخیش او را گفتند: «آیا این داود، پادشاه زمین نیست؟ و آیا در باره او رقص‌کنان سرودخوانده، نگفتند که شاول هزاران خود را و داود ده هزاران خود را کشت؟»"},{"v":12,"t":"و داود این سخنان رادر دل خود جا داده، از اخیش، ملک جت بسیاربترسید."},{"v":13,"t":"و در نظر ایشان رفتار خود راتغییرداده، به حضور ایشان خویشتن را دیوانه نمود، وبر لنگه های در خط می‌کشید و آب دهنش را برریش خود می‌ریخت."},{"v":14,"t":"و اخیش به خادمان خود گفت: «اینک این شخص را می‌بینید که دیوانه است، او را چرا نزد من آوردید؟"},{"v":15,"t":"آیامحتاج به دیوانگان هستم که این شخص راآوردید تا نزد من دیوانگی کند؟ و آیا این شخص داخل خانه من بشود؟»"}]},"22":{"fa":[{"v":1,"t":"و داود از آنجا رفته، به مغاره عدلام فرارکرد و چون برادرانش و تمامی خاندان پدرش شنیدند، آنجا نزد او فرود آمدند."},{"v":2,"t":"و هرکه در تنگی بود و هر قرض دار و هر‌که تلخی جان داشت، نزد او جمع آمدند، و بر ایشان سردار شدو تخمین چهار صد نفر با او بودند."},{"v":3,"t":"و داود از آنجا به مصفه موآب رفته، به پادشاه موآب گفت: «تمنا اینکه پدرم و مادرم نزد شمابیایند تا بدانم خدا برای من چه خواهد کرد.»"},{"v":4,"t":"پس ایشان را نزد پادشاه موآب برد و تمامی روزهایی که داود در آن ملاذ بود، نزد او ساکن بودند."},{"v":5,"t":"و جاد نبی به داود گفت که «در این ملاذدیگر توقف منما بلکه روانه شده، به زمین یهودا برو.» پس داود رفت و به جنگل حارث درآمد."},{"v":6,"t":"و شاول شنید که داود و مردمانی که با وی بودند پیدا شده‌اند، و شاول در جبعه، زیر درخت بلوط در رامه نشسته بود، و نیزه‌اش در دستش، وجمیع خادمانش در اطراف او ایستاده بودند."},{"v":7,"t":"وشاول به خادمانی که در اطرافش ایستاده بودند، گفت: «حال‌ای بنیامینیان بشنوید! آیا پسر یسا به جمیع شما کشتزارها و تاکستانها خواهد داد و آیاهمگی شما را سردار هزاره‌ها و سردار صده هاخواهد ساخت؟"},{"v":8,"t":"که جمیع شما بر من فتنه انگیزشده، کسی مرا اطلاع ندهد که پسر من با پسر یساعهد بسته است و از شما کسی برای من غمگین نمی شود تا مرا خبر دهد که پسر من بنده مرابرانگیخته است تا در کمین بنشیند چنانکه امروزهست.»"},{"v":9,"t":"و دوآغ ادومی که با خادمان شاول ایستاده بود در جواب گفت: «پسر یسا را دیدم که به نوب نزد اخیملک بن اخیتوب درآمد."},{"v":10,"t":"و او ازبرای وی از خداوند سوال نمود و توشه‌ای به اوداد و شمشیر جلیات فلسطینی را نیز به او داد.»"},{"v":11,"t":"پس پادشاه فرستاده، اخیملک بن اخیتوب کاهن و جمیع کاهنان خاندان پدرش را که در نوب بودند طلبید، و تمامی ایشان نزد پادشاه آمدند."},{"v":12,"t":"و شاول گفت: «ای پسر اخیتوب بشنو.» اوگفت: «لبیک‌ای آقایم!»"},{"v":13,"t":"شاول به او گفت: «تو وپسر یسا چرا بر من فتنه انگیختید به اینکه به وی نان و شمشیر دادی و برای وی از خدا سوال نمودی تا به ضد من برخاسته، در کمین بنشیندچنانکه امروز شده است.»"},{"v":14,"t":"اخیملک در جواب پادشاه گفت: «کیست ازجمیع بندگانت که مثل داود امین باشد و او دامادپادشاه است و در مشورت شریک تو و در خانه تومکرم است."},{"v":15,"t":"آیا امروز به سوال نمودن از خدابرای او شروع کردم، حاشا از من. پادشاه این کار رابه بنده خود و به جمیع خاندان پدرم اسناد ندهدزیرا که بنده ات از این چیزها کم یا زیاد ندانسته بود.»"},{"v":16,"t":"پادشاه گفت: «ای اخیملک تو و تمامی خاندان پدرت البته خواهید مرد.»"},{"v":17,"t":"آنگاه پادشاه به شاطرانی که به حضورش ایستاده بودند، گفت: «برخاسته، کاهنان خداوندرا بکشید زیرا که دست ایشان نیز با داود است و بااینکه دانستند که او فرار می‌کند، مرا اطلاع ندادند.» اما خادمان پادشاه نخواستند که دست خود را دراز کرده، بر کاهنان خداوند هجوم آورند."},{"v":18,"t":"پس پادشاه به دوآغ گفت: «تو برگرد وبر کاهنان حمله آور.» و دوآغ ادومی برخاسته، برکاهنان حمله آورد و هشتاد و پنج نفر را که ایفودکتان می‌پوشیدند در آن روز کشت."},{"v":19,"t":"و نوب رانیز که شهر کاهنان است به دم شمشیر زد و مردان و زنان و اطفال و شیرخوارگان و گاوان و الاغان وگوسفندان را به دم شمشیر کشت."},{"v":20,"t":"اما یکی از پسران اخیملک بن اخیتوب که ابیاتار نام داشت رهایی یافته، در عقب داود فرارکرد."},{"v":21,"t":"و ابیاتار داود را مخبر ساخت که شاول کاهنان خداوند را کشت."},{"v":22,"t":"داود به ابیاتار گفت: «روزی که دوآغ ادومی در آنجا بود، دانستم که اوشاول را البته مخبر‌خواهد ساخت، پس من باعث کشته شدن تمامی اهل خاندان پدرت شدم."},{"v":23,"t":"نزد من بمان و مترس زیرا هر‌که قصد جان من دارد قصد جان تو نیز خواهد داشت. و لکن نزد من محفوظ خواهی بود.»"}]},"23":{"fa":[{"v":1,"t":"و به داود خبر داده، گفتند: «اینک فلسطینیان با قعیله جنگ می‌کنند وخرمنها را غارت می‌نماید.»"},{"v":2,"t":"و داود از خداوندسوال کرده، گفت: «آیا بروم و این فلسطینیان راشکست دهم.» خداوند به داود گفت: «برو وفلسطینیان را شکست داده، قعیله را خلاص کن.»"},{"v":3,"t":"و مردمان داود وی را گفتند: «اینک اینجا دریهودا می‌ترسیم پس چند مرتبه زیاده اگر به مقابله لشکرهای فلسطینیان به قعیله برویم.»"},{"v":4,"t":"و داود بار دیگر از خداوند سوال نمود وخداوند او را جواب داده، گفت: «برخیز به قعیله برو زیرا که من فلسطینیان را به‌دست تو خواهم داد.»"},{"v":5,"t":"و داود با مردانش به قعیله رفتند و بافلسطینیان جنگ کرده، مواشی ایشان را بردند، وایشان را به کشتار عظیمی کشتند. پس داودساکنان قعیله را نجات داد."},{"v":6,"t":"و هنگامی که ابیاتار بن اخیملک نزد داود به قعیله فرار کرد، ایفود را در دست خود آورد."},{"v":7,"t":"وبه شاول خبر دادند که داود به قعیله آمده است وشاول گفت: «خدا او را به‌دست من سپرده است، زیرا به شهری که دروازه‌ها و پشت بندها داردداخل شده، محبوس گشته است.»"},{"v":8,"t":"و شاول جمیع قوم را برای جنگ طلبید تا به قعیله فرودشده، داود و مردانش را محاصره نماید."},{"v":9,"t":"و چون داود دانست که شاول شرارت رابرای او اندیشیده است، به ابیاتار کاهن گفت: «ایفود را نزدیک بیاور،"},{"v":10,"t":"و داود گفت: «ای یهوه، خدای اسرائیل، بنده ات شنیده است که شاول عزیمت دارد که به قعیله بیاید تا به‌خاطر من شهررا خراب کند."},{"v":11,"t":"آیا اهل قعیله مرا به‌دست اوتسلیم خواهند نمود؟ و آیا شاول چنانکه بنده ات شنیده است، خواهد آمد؟ ای یهوه، خدای اسرائیل، مسالت آنکه بنده خود را خبر دهی.» خداوند گفت که او خواهد آمد."},{"v":12,"t":"داود گفت: «آیا اهل قعیله مرا و کسان مرا به‌دست شاول تسلیم خواهند نمود؟» خداوند گفت که «تسلیم خواهند نمود.»"},{"v":13,"t":"پس داود و مردانش که تخمین ششصد نفربودند، برخاسته، از قعیله بیرون رفتند و هر جایی که توانستند بروند، رفتند. و چون به شاول خبردادند که داود از قعیله فرار کرده است، از بیرون رفتن بازایستاد."},{"v":14,"t":"و داود در بیابان در ملاذهانشست و در کوهی در بیابان زیف توقف نمود. وشاول همه روزه او را می‌طلبید لیکن خداوند او رابه‌دستش تسلیم ننمود."},{"v":15,"t":"و داود دید که شاول به قصد جان او بیرون آمده است و داود در بیابان زیف در جنگل ساکن بود."},{"v":16,"t":"و یوناتان، پسر شاول، به جنگل آمده، دست او را به خدا تقویت نمود."},{"v":17,"t":"و او را گفت: «مترس زیرا که دست پدر من، شاول تو را نخواهدجست، و تو بر اسرائیل پادشاه خواهی شد، و من دومین تو خواهم بود و پدرم شاول نیز این رامی داند.»"},{"v":18,"t":"و هر دوی ایشان به حضور خداوندعهد بستند و داود به جنگل برگشت و یوناتان به خانه خود رفت."},{"v":19,"t":"و زیفیان نزد شاول به جبعه آمده، گفتند: «آیا داود در ملاذهای جنگل در کوه حخیله که به طرف جنوب بیابان است، خود را نزد ما پنهان نکرده است؟"},{"v":20,"t":"پس‌ای پادشاه چنانکه دلت کمال آرزو برای آمدن دارد بیا و تکلیف ما این است که او را به‌دست پادشاه تسلیم نماییم.»"},{"v":21,"t":"شاول گفت: «شما از جانب خداوند مبارک باشید چونکه بر من دلسوزی نمودید."},{"v":22,"t":"پس بروید و بیشتر تحقیق نموده، جایی را که آمد ورفت می‌کند ببینید و بفهمید، و دیگر اینکه کیست که او را در آنجا دیده است، زیرا به من گفته شد که بسیار با مکر رفتار می‌کند."},{"v":23,"t":"پس ببینید و جمیع مکانهای مخفی را که خود را در آنها پنهان می‌کندبدانید و حقیقت حال را به من باز رسانید تا با شمابیایم و اگر در این زمین باشد او را از جمیع هزاره های یهودا پیدا خواهم کرد.»"},{"v":24,"t":"پس برخاسته، پیش روی شاول به زیف رفتند."},{"v":25,"t":"و شاول و مردان اوبه تفحص او رفتند و چون داود را خبر دادند، اونزد صخره فرود آمده، در بیابان معون ساکن شد وشاول چون این را شنید، داود را در بیابان معون تعاقب نمود."},{"v":26,"t":"و شاول به یک طرف کوه می‌رفت و داود و کسانش به طرف دیگر کوه، و داودمی شتافت که از حضور شاول بگریزد و شاول ومردانش داود و کسانش را احاطه نمودند تا ایشان را بگیرند."},{"v":27,"t":"اما قاصدی نزد شاول آمده، گفت: «بشتاب و بیا زیرا که فلسطینیان به زمین حمله آورده‌اند."},{"v":28,"t":"پس شاول از تعاقب نمودن داود برگشته، به مقابله فلسطینیان رفت، بنابراین آن مکان را صخره محلقوت نامیدند."}]},"24":{"fa":[{"v":1,"t":"و واقع شد بعد از برگشتن شاول از عقب فلسطینیان که او را خبر داده، گفتند: «اینک داود در بیابان عین جدی است.»"},{"v":2,"t":"و شاول سه هزار نفر برگزیده را از تمامی اسرائیل گرفته، برای جستجوی داود و کسانش بر صخره های بزهای کوهی رفت."},{"v":3,"t":"و به‌سر راه به آغلهای گوسفندان که در آنجا مغاره‌ای بود، رسید. وشاول داخل آن شد تا پایهای خود را بپوشاند. وداود و کسان او در جانبهای مغاره نشسته بودند."},{"v":4,"t":"و کسان داود وی را گفتند: «اینک روزی که خداوند به تو وعده داده است که همانا دشمن تورا به‌دستت تسلیم خواهم نمود تا هر‌چه درنظرت پسند آید به او عمل نمایی.» و داودبرخاسته، دامن ردای شاول را آهسته برید."},{"v":5,"t":"وبعد از آن دل داود مضطرب شد از این جهت که دامن شاول را بریده بود."},{"v":6,"t":"و به کسان خود گفت: «حاشا بر من از جانب خداوند که این امر را به آقای خود مسیح خداوند بکنم، و دست خود رابر او دراز نمایم چونکه او مسیح خداوند است.»"},{"v":7,"t":"پس داود کسان خود را به این سخنان توبیخ نموده، ایشان را نگذاشت که بر شاول برخیزند، وشاول از مغاره برخاسته، راه خود را پیش گرفت."},{"v":8,"t":"و بعد از آن، داود برخاسته، از مغاره بیرون رفت و در عقب شاول صدا زده، گفت: «ای آقایم پادشاه.» و چون شاول به عقب خود نگریست داود رو به زمین خم شده، تعظیم کرد."},{"v":9,"t":"و داود به شاول گفت: «چرا سخنان مردم را می‌شنوی که می‌گویند اینک داود قصد اذیت تو را دارد."},{"v":10,"t":"اینک امروز چشمانت دیده است که چگونه خداوند تو را در مغاره امروز به‌دست من تسلیم نمود، و بعضی گفتند که تو را بکشم، اما چشمم برتو شفقت نموده، گفتم دست خود را بر آقای خویش دراز نکنم، زیرا که مسیح خداوند است."},{"v":11,"t":"و‌ای پدرم ملاحظه کن و دامن ردای خود را دردست من ببین، زیرا از اینکه جامه تو را بریدم و تورا نکشتم بدان و ببین که بدی و خیانت در دست من نیست، و به تو گناه نکرده‌ام، اما تو جان مراشکار می‌کنی تا آن را گرفتار سازی."},{"v":12,"t":"خداونددر میان من و تو حکم نماید، و خداوند انتقام مرااز تو بکشد اما دست من بر تو نخواهد شد."},{"v":13,"t":"چنانکه مثل قدیمان می‌گوید که شرارت ازشریران صادر می‌شود اما دست من بر تو نخواهدشد."},{"v":14,"t":"و در عقب کیست که پادشاه اسرائیل بیرون می‌آید و کیست که او را تعاقب می‌نمایی، در عقب سگ مرده‌ای بلکه در عقب یک کیک!"},{"v":15,"t":"پس خداوند داور باشد و میان من و تو حکم نماید و ملاحظه کرده دعوی مرا با تو فیصل کند ومرا از دست تو برهاند.»"},{"v":16,"t":"و چون داود از گفتن این سخنان به شاول فارغ شد، شاول گفت: «آیا این آواز توست‌ای پسر من داود.» و شاول آواز خود را بلند کرده، گریست."},{"v":17,"t":"و به داود گفت: «تو از من نیکوترهستی زیرا که تو جزای نیکو به من رسانیدی و من جزای بد به تو رسانیدم."},{"v":18,"t":"و تو امروز ظاهرکردی که چگونه به من احسان نمودی چونکه خداوند مرا به‌دست تو تسلیم کرده، و مرانکشتی."},{"v":19,"t":"و اگر کسی دشمن خویش را بیابد، آیا او را به نیکویی رها نماید؟ پس خداوند تو را به نیکویی جزا دهد به‌سبب آنچه امروز به من کردی."},{"v":20,"t":"و حال اینک می‌دانم که البته پادشاه خواهی شد و سلطنت اسرائیل در دست تو ثابت خواهد گردید."},{"v":21,"t":"پس الان برای من قسم به خداوند بخور که بعد از من ذریه مرا منقطع نسازی، و اسم مرا از خاندان پدرم محو نکنی.»"},{"v":22,"t":"و داود برای شاول قسم خورد، و شاول به خانه خود رفت و داود و کسانش به مامن خویش آمدند."}]},"25":{"fa":[{"v":1,"t":"و سموئیل وفات نمود، و تمامی اسرائیل جمع شده، از برایش نوحه گری نمودند، و او را در خانه‌اش در رامه دفن نمودند و داود برخاسته، به بیابان فاران فرود شد."},{"v":2,"t":"و در معون کسی بود که املاکش در کرمل بود و آن مرد بسیار بزرگ بود و سه هزار گوسفند وهزار بز داشت، و گوسفندان خود را در کرمل پشم می‌برید."},{"v":3,"t":"و اسم آن شخص نابال بود و اسم زنش ابیجایل. و آن زن نیک فهم و خوش منظر بود. اماآن مرد سخت دل و بدرفتار و از خاندان کالیب بود."},{"v":4,"t":"و داود در بیابان شنید که نابال گله خود راپشم می‌برد."},{"v":5,"t":"پس داود ده خادم فرستاد و داود به خادمان خود گفت که «به کرمل برآیید و نزد نابال رفته، اززبان من سلامتی او را بپرسید."},{"v":6,"t":"و چنین گویید: زنده باش و سلامتی بر تو باد و بر خاندان تو و برهرچه داری سلامتی باشد."},{"v":7,"t":"و الان شنیده‌ام که پشم برندگان داری و به شبانان تو که در این اوقات نزد ما بودند، اذیت نرسانیدیم. همه روزهایی که در کرمل بودند چیزی از ایشان گم نشد."},{"v":8,"t":"از خادمان خود بپرس و تو را خواهند گفت. پس خادمان در نظر تو التفات یابند زیرا که در روزسعادتمندی آمده‌ایم، تمنا اینکه آنچه دستت بیابد به بندگانت و پسرت داود بدهی.»"},{"v":9,"t":"پس خادمان داود آمدند و جمیع این سخنان را از زبان داود به نابال گفته، ساکت شدند."},{"v":10,"t":"ونابال به خادمان داود جواب داده، گفت: «داودکیست و پسر یسا کیست؟ امروز بسا بندگان هریکی از آقای خویش می‌گریزند."},{"v":11,"t":"آیا نان و آب خود را و گوشت را که برای پشم برندگان خودذبح نموده‌ام، بگیرم و به کسانی که نمی دانم از کجاهستند بدهم.»"},{"v":12,"t":"پس خادمان داود برگشته، مراجعت نمودند و آمده، داود را از جمیع این سخنان مخبر ساختند."},{"v":13,"t":"و داود به مردان خودگفت: «هر یک از شما شمشیر خود را ببندد.» وهریک شمشیر خود را بستند، و داود نیز شمشیرخود را بست و تخمین چهارصد نفر از عقب داودرفتند، و دویست نفر نزد اسباب ماندند."},{"v":14,"t":"و خادمی از خادمانش به ابیجایل، زن نابال، خبر داده، گفت: «اینک داود، قاصدان از بیابان فرستاد تا آقای مرا تحیت گویند و او ایشان رااهانت نمود."},{"v":15,"t":"و آن مردمان احسان بسیار به مانمودند و همه روزهایی که در صحرا بودیم و باایشان معاشرت داشتیم اذیتی به ما نرسید وچیزی از ما گم نشد."},{"v":16,"t":"و تمام روزهایی که باایشان گوسفندان را می‌چرانیدیم هم در شب وهم در روز برای ما مثل حصار بودند."},{"v":17,"t":"پس الان بدان و ببین که چه باید بکنی زیرا که بدی برای آقای ما و تمامی خاندانش مهیاست، چونکه او به حدی پسر بلیعال است که احدی با وی سخن نتواند گفت.»"},{"v":18,"t":"آنگاه ابیجایل تعجیل نموده، دویست گرده نان و دو مشگ شراب و پنج گوسفند مهیا شده، وپنج کیل خوشه برشته و صد قرص کشمش ودویست قرص انجیر گرفته، آنها را بر الاغهاگذاشت."},{"v":19,"t":"و به خادمان خود گفت: «پیش من بروید و اینک من از عقب شما می‌آیم.» اما به شوهر خود نابال هیچ خبر نداد."},{"v":20,"t":"و چون بر الاغ خود سوار شده، از سایه کوه به زیر می‌آمد، اینک داود و کسانش به مقابل او رسیدند و به ایشان برخورد."},{"v":21,"t":"و داود گفته بود: «به تحقیق که تمامی مایملک این شخص را در بیابان عبث نگاه داشتم که از جمیع اموالش چیزی گم نشد و او بدی را به عوض نیکویی به من پاداش داده است."},{"v":22,"t":"خدا به دشمنان داود چنین بلکه زیاده از این عمل نمایداگر از همه متعلقان او تا طلوع صبح ذکوری واگذارم.»"},{"v":23,"t":"و چون ابیجایل، داود را دید، تعجیل نموده، از الاغ پیاده شد و پیش داود به روی خودبه زمین افتاده، تعظیم نمود."},{"v":24,"t":"و نزد پایهایش افتاده، گفت: «ای آقایم این تقصیر بر من باشد وکنیزت در گوش تو سخن بگوید، و سخنان کنیزخود را بشنو."},{"v":25,"t":"و آقایم دل خود را بر این مردبلیعال، یعنی نابال مشغول نسازد، زیرا که اسمش مثل خودش است اسمش نابال است و حماقت بااوست، لیکن من کنیز تو خادمانی را که آقایم فرستاده بود، ندیدم."},{"v":26,"t":"و الان‌ای آقایم به حیات خداوند و به حیات جان تو چونکه خداوند تو رااز ریختن خون و از انتقام کشیدن به‌دست خودمنع نموده است، پس الان دشمنانت و جویندگان ضرر آقایم مثل نابال بشوند."},{"v":27,"t":"و الان این هدیه‌ای که کنیزت برای آقای خود آورده است به غلامانی که همراه آقایم می‌روند، داده شود."},{"v":28,"t":"و تقصیر کنیز خود را عفو نما زیرا به درستی که خداوند برای آقایم خانه استوار بنا خواهد نمود، چونکه آقایم در جنگهای خداوند می‌کوشد وبدی در تمام روزهایت به تو نخواهد رسید."},{"v":29,"t":"واگر‌چه کسی برای تعاقب تو و به قصد جانت برخیزد، اما جان آقایم در دسته حیات، نزد یهوه، خدایت، بسته خواهد شد. و اما جان دشمنانت راگویا از میان کفه فلاخن خواهد انداخت."},{"v":30,"t":"وهنگامی که خداوند بر‌حسب همه احسانی که برای آقایم وعده داده است، عمل آورد، و تو راپیشوا بر اسرائیل نصب نماید."},{"v":31,"t":"آنگاه این برای تو سنگ مصادم و به جهت آقایم لغزش دل نخواهد بود که خون بی‌جهت ریخته‌ای و آقایم انتقام خود را کشیده باشد، و چون خداوند به آقایم احسان نماید آنگاه کنیز خود را بیاد آور.»"},{"v":32,"t":"داود به ابیجایل گفت: «یهوه، خدای اسرائیل، متبارک باد که تو را امروز به استقبال من فرستاد."},{"v":33,"t":"و حکمت تو مبارک و تو نیز مبارک باشی که امروز مرا از ریختن خون و از کشیدن انتقام خویش به‌دست خود منع نمودی."},{"v":34,"t":"ولیکن به حیات یهوه، خدای اسرائیل، که مرا ازرسانیدن اذیت به تو منع نمود. اگر تعجیل ننموده، به استقبال من نمی آمدی البته تا طلوع صبح برای نابال ذکوری باقی نمی ماند.»"},{"v":35,"t":"پس داود آنچه را که به جهت او آورده بود، از دستش پذیرفته، به او گفت: «به سلامتی به خانه ات برو وببین که سخنت را شنیده، تو را مقبول داشتم.»"},{"v":36,"t":"پس ابیجایل نزد نابال برگشت و اینک اوضیافتی مثل ضیافت ملوکانه در خانه خودمی داشت و دل نابال در اندرونش شادمان بودچونکه بسیار مست بود و تا طلوع صبح چیزی کم یا زیاد به او خبر نداد."},{"v":37,"t":"و بامدادان چون شراب از نابال بیرون رفت، زنش این چیزها را به او بیان کرد و دلش در اندرونش مرده گردید و خود مثل سنگ شد."},{"v":38,"t":"و واقع شد که بعد از ده روز خداوندنابال را مبتلا ساخت که بمرد."},{"v":39,"t":"و چون داود شنید که نابال مرده است، گفت: «مبارک باد خداوند که انتقام عار مرا ازدست نابال کشیده، و بنده خود را از بدی نگاه داشته است، زیرا خداوند شرارت نابال را به‌سرش رد نموده است و داود فرستاده، با ابیجایل سخن گفت تا او را به زنی خود بگیرد.»"},{"v":40,"t":"وخادمان داود نزد ابیجایل به کرمل آمده، با وی مکالمه کرده، گفتند: «داود ما را نزد تو فرستاده است تا تو را برای خویش به زنی بگیرد.»"},{"v":41,"t":"و اوبرخاسته، رو به زمین خم شد و گفت: «اینک کنیزت بنده است تا پایهای خادمان آقای خود رابشوید.»"},{"v":42,"t":"و ابیجایل تعجیل نموده، برخاست وبر الاغ خود سوار شد و پنج کنیزش همراهش روانه شدند و از عقب قاصدان داود رفته، زن اوشد."},{"v":43,"t":"و داود اخینوعم یزرعیلیه را نیز گرفت وهردوی ایشان زن او شدند."},{"v":44,"t":"و شاول دخترخود، میکال، زن داود را به فلطی ابن لایش که ازجلیم بود، داد."}]},"26":{"fa":[{"v":1,"t":"پس زیفیان نزد شاول به جبعه آمده، گفتند: «آیا داود خویشتن را در تل حخیله که در مقابل بیابان است، پنهان نکرده است؟»"},{"v":2,"t":"آنگاه شاول برخاسته، به بیابان زیف فرود شد و سه هزار مرد از برگزیدگان اسرائیل همراهش رفتند تا داود را در بیابان زیف جستجونماید."},{"v":3,"t":"و شاول در تل حخیله که در مقابل بیابان به‌سر راه است اردو زد، و داود در بیابان ساکن بود، و چون دید که شاول در عقبش در بیابان آمده است،"},{"v":4,"t":"داود جاسوسان فرستاده، دریافت کرد که شاول به تحقیق آمده است."},{"v":5,"t":"و داود برخاسته، به‌جایی که شاول در آن اردو زده بود، آمد. و داود مکانی را که شاول وابنیر، پسر نیر، سردار لشکرش خوابیده بودند، ملاحظه کرد، و شاول در اندرون سنگرمی خوابید و قوم در اطراف او فرود آمده بودند."},{"v":6,"t":"و داود به اخیملک حتی و ابیشای ابن صرویه برادر یوآب خطاب کرده، گفت: «کیست که همراه من نزد شاول به اردو بیاید؟» ابیشای گفت: «من همراه تو می‌آیم.»"},{"v":7,"t":"پس داود و ابیشای در شب به میان قوم آمدند و اینک شاول در اندرون سنگردراز شده، خوابیده بود، و نیزه‌اش نزد سرش درزمین کوبیده، و ابنیر و قوم در اطرافش خوابیده بودند."},{"v":8,"t":"و ابیشای به داود گفت: «امروز خدا، دشمن تو را به‌دستت تسلیم نموده. پس الان اذن بده تا او را با نیزه یک دفعه به زمین بدوزم و او رادوباره نخواهم زد.»"},{"v":9,"t":"و داود به ابیشای گفت: «اورا هلاک مکن زیرا کیست که به مسیح خداونددست خود را دراز کرده، بی‌گناه باشد."},{"v":10,"t":"و داودگفت: «به حیات یهوه قسم که یا خداوند او راخواهد زد یا اجلش رسیده، خواهد مرد یا به جنگ فرود شده، هلاک خواهد گردید."},{"v":11,"t":"حاشابر من از خداوند که دست خود را بر مسیح خداوند دراز کنم اما الان نیزه‌ای را که نزد سرش است و سبوی آب را بگیر و برویم.»"},{"v":12,"t":"پس داودنیزه و سبوی آب را از نزد سر شاول گرفت و روانه شدند، و کسی نبود که ببیند و بداند یا بیدار شودزیرا جمیع ایشان در خواب بودند، چونکه خواب سنگین از خداوند بر ایشان مستولی شده بود."},{"v":13,"t":"و داود به طرف دیگر گذشته، از دور به‌سرکوه بایستاد و مسافت عظیمی در میان ایشان بود."},{"v":14,"t":"و داود قوم و ابنیر پسر نیر را صدا زده، گفت: «ای ابنیر جواب نمی دهی؟» و ابنیر جواب داده، گفت: «تو کیستی که پادشاه را می‌خوانی؟»"},{"v":15,"t":"داود به ابنیر گفت: «آیا تو مرد نیستی و دراسرائیل مثل تو کیست؟ پس چرا آقای خودپادشاه را نگاهبانی نمی کنی؟ زیرا یکی از قوم آمد تا آقایت پادشاه را هلاک کند."},{"v":16,"t":"این کار که کردی خوب نیست، به حیات یهوه، شمامستوجب قتل هستید، چونکه آقای خود مسیح خداوند را نگاهبانی نکردید، پس الان ببین که نیزه پادشاه و سبوی آب که نزد سرش بود، کجاست؟»"},{"v":17,"t":"و شاول آواز داود را شناخته، گفت: «آیااین آواز توست‌ای پسر من داود؟» و داود گفت: «ای آقایم پادشاه آواز من است.»"},{"v":18,"t":"و گفت: «این از چه سبب است که آقایم بنده خود را تعاقب می‌کند؟ زیرا چه کردم و چه بدی در دست من است؟"},{"v":19,"t":"پس الان آقایم پادشاه سخنان بنده خودرا بشنود، اگر خداوند تو را بر من تحریک نموده است پس هدیه‌ای قبول نماید، و اگر بنی آدم باشند پس ایشان به حضور خداوند ملعون باشند، زیرا که امروز مرا از التصاق به نصیب خداوندمی رانند و می‌گویند برو و خدایان غیر را عبادت نما."},{"v":20,"t":"و الان خون من از حضور خداوند به زمین ریخته نشود زیرا که پادشاه اسرائیل مثل کسی‌که کبک را بر کوه‌ها تعاقب می‌کند به جستجوی یک کیک بیرون آمده است.»"},{"v":21,"t":"شاول گفت: «گناه ورزیدم‌ای پسرم داود! برگرد و تو را دیگر اذیت نخواهم کرد، چونکه امروز جان من در نظر تو عزیز آمد اینک احمقانه رفتار نمودم و بسیار گمراه شدم.»"},{"v":22,"t":"داود درجواب گفت: «اینک نیزه پادشاه! پس یکی ازغلامان به اینجا گذشته، آن را بگیرد."},{"v":23,"t":"و خداوندهر کس را بر‌حسب عدالت و امانتش پاداش دهد، چونکه امروز خداوند تو را به‌دست من سپرده بود. اما نخواستم دست خود را بر مسیح خداونددراز کنم."},{"v":24,"t":"و اینک چنانکه جان تو امروز در نظرمن عظیم آمد جان من در نظر خداوند عظیم باشدو مرا از هر تنگی برهاند.»"},{"v":25,"t":"شاول به داود گفت: «مبارک باش‌ای پسرم داود، البته کارهای عظیم خواهی کرد و غالب خواهی شد.» پس داود راه خود را پیش گرفت و شاول به‌جای خودمراجعت کرد."}]},"27":{"fa":[{"v":1,"t":"و داود در دل خود گفت: «الحال روزی به‌دست شاول هلاک خواهم شد. چیزی برای من از این بهتر نیست که به زمین فلسطینیان فرار کنم، و شاول از جستجوی من درتمامی حدود اسرائیل مایوس شود. پس از دست او نجات خواهم یافت.»"},{"v":2,"t":"پس داود برخاسته، باآن ششصد نفر که همراهش بودند نزد اخیش بن معوک، پادشاه جت گذشت."},{"v":3,"t":"و داود نزد اخیش در جت ساکن شد، او و مردمانش هرکس با اهل خانه‌اش، و داود با دو زنش اخینوعم یزرعیلیه وابیجایل کرملیه زن نابال."},{"v":4,"t":"و به شاول گفته شد که داود به جت فرار کرده است، پس او را دیگرجستجو نکرد."},{"v":5,"t":"و داود به اخیش گفت: «الان اگر من در نظر توالتفات یافتم مکانی به من در یکی از شهرهای صحرا بدهند تا در آنجا ساکن شوم، زیرا که بنده تو چرا در شهر دارالسلطنه با تو ساکن شود.»"},{"v":6,"t":"پس اخیش در آن روز صقلغ را به او داد، لهذاصقلغ تا امروز از آن پادشاهان یهوداست."},{"v":7,"t":"وعدد روزهایی که داود در بلاد فلسطینیان ساکن بود یک سال و چهار ماه بود."},{"v":8,"t":"و داود و مردانش برآمده، بر جشوریان وجرزیان و عمالقه هجوم آوردند زیرا که این طوایف در ایام قدیم در آن زمین از شور تا به زمین مصر ساکن می‌بودند."},{"v":9,"t":"و داود اهل آن زمین راشکست داده، مرد یا زنی زنده نگذاشت وگوسفندان و گاوان و الاغها و شتران و رخوت گرفته، برگشت و نزد اخیش آمد."},{"v":10,"t":"و اخیش گفت: «امروز به کجا تاخت آوردید.» داود گفت: «بر جنوبی یهودا و جنوب یرحمئیلیان و به جنوب قینیان."},{"v":11,"t":"و داود مرد یا زنی را زنده نگذاشت که به جت بیایند زیرا گفت مبادا درباره ما خبر‌آورده، بگویند که داود چنین کرده است وتمامی روزهایی که در بلاد فلسطینیان بماند، عادتش چنین خواهد بود.»"},{"v":12,"t":"و اخیش داود را تصدیق نموده، گفت: «خویشتن را نزد قوم خود اسرائیل بالکل مکروه نموده است، پس تا به ابد بنده من خواهد بود.»"}]},"28":{"fa":[{"v":1,"t":"و واقع شد در آن ایام که فلسطینیان لشکرهای خود را برای جنگ فراهم آوردند تا با اسرائیل مقاتله نمایند، و اخیش به داود گفت: «یقین بدان که تو و کسانت همراه من به اردو بیرون خواهید آمد.»"},{"v":2,"t":"داود به اخیش گفت: «به تحقیق خواهی دانست که بنده تو چه خواهدکرد.» اخیش به داود گفت: «از این جهت تو راهمیشه اوقات نگاهبان سرم خواهم ساخت.»"},{"v":3,"t":"و سموئیل وفات نموده بود، و جمیع اسرائیل به جهت او نوحه گری نموده، او را درشهرش رامه دفن کرده بودند، و شاول تمامی اصحاب اجنه و فالگیران را از زمین بیرون کرده بود."},{"v":4,"t":"و فلسطینیان جمع شده، آمدند و در شونیم اردو زدند، و شاول تمامی اسرائیل را جمع کرده، در جلبوع اردو زدند."},{"v":5,"t":"و چون شاول لشکرفلسطینیان را دید، بترسید و دلش بسیار مضطرب شد."},{"v":6,"t":"و شاول از خداوند سوال نمود و خداوند اورا جواب نداد، نه به خوابها و نه به اوریم و نه به انبیا."},{"v":7,"t":"و شاول به خادمان خود گفت: «زنی را که صاحب اجنه باشد، برای من بطلبید تا نزد او رفته، از او مسالت نمایم.» خادمانش وی را گفتند: «اینک زنی صاحب اجنه در عین دور می‌باشد.»"},{"v":8,"t":"و شاول صورت خویش را تبدیل نموده، لباس دیگر پوشید و دو نفر همراه خود برداشته، رفت و شبانگاه نزد آن زن آمده، گفت: «تمنا اینکه به واسطه جن برای من فالگیری نمایی و کسی راکه به تو بگویم از برایم برآوری.»"},{"v":9,"t":"آن زن وی راگفت: «اینک آنچه شاول کرده است می‌دانی که چگونه اصحاب اجنه و فالگیران را از زمین منقطع نموده است، پس تو چرا برای جانم دام می‌گذاری تا مرا به قتل رسانی؟»"},{"v":10,"t":"و شاول برای وی به یهوه قسم خورده، گفت: «به حیات یهوه قسم که از این امر به تو هیچ بدی نخواهد رسید.»"},{"v":11,"t":"آن زن گفت: «از برایت که را برآورم؟» او گفت: «سموئیل را برای من برآور.»"},{"v":12,"t":"و چون آن زن سموئیل را دید به آواز بلند صدا زد و زن، شاول را خطاب کرده، گفت: «برای چه مرا فریب دادی زیرا تو شاول هستی.»"},{"v":13,"t":"پادشاه وی را گفت: «مترس! چه دیدی؟» آن زن در جواب شاول گفت: «خدایی را می‌بینم که از زمین بر می‌آید.»"},{"v":14,"t":"او وی را گفت: «صورت او چگونه است؟» زن گفت: «مردی پیر بر می‌آید و به ردایی ملبس است.» پس شاول دانست که سموئیل است و روبه زمین خم شده، تعظیم کرد."},{"v":15,"t":"و سموئیل به شاول گفت: «چرا مرابرآورده، مضطرب ساختی؟» شاول گفت: «درشدت تنگی هستم چونکه فلسطینیان با من جنگ می‌نمایند و خدا از من دور شده، مرا نه به واسطه انبیا و نه به خوابها دیگر جواب می‌دهد، لهذا تو راخواندم تا مرا اعلام نمایی که چه باید بکنم.»"},{"v":16,"t":"سموئیل گفت: «پس چرا از من سوال می‌نمایی و حال آنکه خداوند از تو دور شده، دشمنت گردیده است."},{"v":17,"t":"و خداوند به نحوی که به زبان من گفته بود، برای خود عمل نموده است، زیراخداوند سلطنت را از دست تو دریده، آن را به همسایه ات داود داده است."},{"v":18,"t":"چونکه آوازخداوند را نشنیدی و شدت غضب او را برعمالیق به عمل نیاوردی، بنابراین خداوند امروزاین عمل را به تو نموده است."},{"v":19,"t":"و خداونداسرائیل را نیز با تو به‌دست فلسطینیان خواهدداد، و تو و پسرانت فردا نزد من خواهید بود، و خداوند اردوی اسرائیل را نیز به‌دست فلسطینیان خواهد داد.»"},{"v":20,"t":"و شاول فور به تمامی قامتش بر زمین افتاد، و از سخنان سموئیل بسیار بترسید. وچونکه تمامی روز و تمامی شب نان نخورده بود، هیچ قوت نداشت."},{"v":21,"t":"و چون آن زن نزد شاول آمده، دید که بسیار پریشان حال است وی راگفت: «اینک کنیزت آواز تو را شنید و جانم را به‌دست خود گذاشتم و سخنانی را که به من گفتی اطاعت نمودم."},{"v":22,"t":"پس حال تمنا اینکه تو نیز آوازکنیز خود را بشنوی تا لقمه‌ای نان به حضورت بگذارم و بخوری تا قوت یافته، به راه خودبروی.»"},{"v":23,"t":"اما او انکار نموده، گفت: «نمی خورم.» لیکن چون خادمانش و آن زن نیز اصرار نمودند، آواز ایشان را بشنید و از زمین برخاسته، بر بسترنشست."},{"v":24,"t":"و آن زن گوساله‌ای پرواری در خانه داشت. پس تعجیل نموده، آن را ذبح کرد و آردگرفته، خمیر ساخت و قرصهای نان فطیر پخت."},{"v":25,"t":"و آنها را نزد شاول و خادمانش گذاشت که خوردند. پس برخاسته، در آن شب روانه شدند."}]},"29":{"fa":[{"v":1,"t":"و فلسطینیان همه لشکرهای خود را درافیق جمع کردند، و اسرائیلیان نزدچشمه‌ای که در یزرعیل است، فرود آمدند."},{"v":2,"t":"وسرداران فلسطینیان صدها و هزارها می‌گذشتند، و داود و مردانش با اخیش در دنباله ایشان می‌گذشتند."},{"v":3,"t":"و سرداران فلسطینیان گفتند که «این عبرانیان کیستند؟» و اخیش به جواب سرداران فلسطینیان گفت: «مگر این داود، بنده شاول، پادشاه اسرائیل نیست که نزد من این‌روزهایا این سالها بوده است و از روزی که نزد من آمد تاامروز در او عیبی نیافتم.»"},{"v":4,"t":"اما سرداران فلسطینیان بر وی غضبناک شدند، و سرداران فلسطینیان او را گفتند: «این مردرا باز گردان تا به‌جایی که برایش تعیین کرده‌ای برگردد، و با ما به جنگ نیاید، مبادا در جنگ دشمن ما بشود، زیرا این کس با چه چیز با آقای خود صلح کند آیا نه با سرهای این مردمان؟"},{"v":5,"t":"آیااین داود نیست که درباره او با یکدیگر رقص کرده، می‌سراییدند و می‌گفتند: «شاول هزارهای خود و داود ده هزارهای خویش را کشته است.»"},{"v":6,"t":"آنگاه اخیش داود را خوانده، او را گفت: «به حیات یهوه قسم که تو مرد راست هستی و خروج و دخول تو با من در اردو به نظر من پسند آمد، زیرا از روز آمدنت نزد من تا امروز از تو بدی ندیده‌ام لیکن در نظر سرداران پسند نیستی."},{"v":7,"t":"پس الان برگشته، به سلامتی برو مبادا مرتکب عملی شوی که در نظر سرداران فلسطینیان ناپسند آید.»"},{"v":8,"t":"و داود به اخیش گفت: «چه کرده‌ام و از روزی که به حضور تو بوده‌ام تا امروز در بنده ات چه یافته‌ای تا آنکه به جنگ نیایم و با دشمنان آقایم پادشاه جنگ ننمایم؟»"},{"v":9,"t":"اخیش در جواب داود گفت: «می‌دانم که تودر نظر من مثل فرشته خدا نیکو هستی لیکن سرداران فلسطینیان گفتند که با ما به جنگ نیاید."},{"v":10,"t":"پس الحال بامدادان با بندگان آقایت که همراه تو آمده‌اند، برخیز و چون بامدادان برخاسته باشید و روشنایی برای شما بشود، روانه شوید.»"},{"v":11,"t":"پس داود با کسان خود صبح زود برخاستند تا روانه شده، به زمین فلسطینیان برگردند وفلسطینیان به یزرعیل برآمدند."}]},"30":{"fa":[{"v":1,"t":"و واقع شد چون داود و کسانش در روزسوم به صقلغ رسیدند که عمالقه برجنوب و بر صقلغ هجوم آورده بودند، و صقلغ رازده آن را به آتش سوزانیده بودند."},{"v":2,"t":"و زنان و همه کسانی را که در آن بودند از خرد و بزرگ اسیرکرده، هیچ‌کس را نکشته، بلکه همه را به اسیری برده، به راه خود رفته بودند."},{"v":3,"t":"و چون داود وکسانش به شهر رسیدند، اینک به آتش سوخته، وزنان و پسران و دختران ایشان اسیر شده بودند."},{"v":4,"t":"پس داود و قومی که همراهش بودند آواز خودرا بلند کرده، گریستند تا طاقت گریه کردن دیگرنداشتند."},{"v":5,"t":"و دو زن داود اخینوعم یزرعیلیه وابیجایل، زن نابال کرملی، اسیر شده بودند."},{"v":6,"t":"وداود بسیار مضطرب شد زیرا که قوم می‌گفتند که او را سنگسار کنند، چون جان تمامی قوم هر یک برای پسران و دختران خویش بسیار تلخ شده بود، اما داود خویشتن را از یهوه، خدای خود، تقویت نمود."},{"v":7,"t":"و داود به ابیاتار کاهن، پسر اخیملک گفت: «ایفود را نزد من بیاور.» و ابیاتار ایفود را نزد داودآورد."},{"v":8,"t":"و داود از خداوند سوال نموده، گفت: «اگر این فوج را تعاقب نمایم، آیا به آنها خواهم رسید؟» او وی را گفت: «تعاقب نما زیرا که به تحقیق خواهی رسید و رها خواهی کرد.»"},{"v":9,"t":"پس داود و ششصد نفر که همراهش بودند روانه شده، به وادی بسور آمدند و واماندگان در آنجا توقف نمودند."},{"v":10,"t":"و داود با چهارصد نفر تعاقب نمود ودویست نفر توقف نمودند زیرا به حدی خسته شده بودند که از وادی بسور نتوانستند گذشت."},{"v":11,"t":"پس شخصی مصری در صحرا یافته، او رانزد داود آوردند و به او نان دادند که خورد و او راآب نوشانیدند."},{"v":12,"t":"و پاره‌ای از قرص انجیر و دوقرص کشمش به او دادند و چون خورد روحش به وی بازگشت زیرا که سه روز و سه شب نه نان خورده، و نه آب نوشیده بود."},{"v":13,"t":"و داود او راگفت: «از آن که هستی و از کجا می‌باشی؟» اوگفت: «من جوان مصری و بنده شخص عمالیقی هستم، و آقایم مرا ترک کرده است زیرا سه روزاست که بیمار شده‌ام."},{"v":14,"t":"ما به جنوب کریتیان و برملک یهودا و بر جنوب کالیب تاخت آوردیم. صقلغ را به آتش سوزانیدیم.»"},{"v":15,"t":"داود وی راگفت: «آیا مرا به آن گروه خواهی رسانید؟» اوگفت: «برای من به خدا قسم بخور که نه مرا بکشی و نه مرا به‌دست آقایم تسلیم کنی، پس تو را نزدآن گروه خواهم رسانید.»"},{"v":16,"t":"و چون او را به آنجا رسانید اینک بر روی تمامی زمین منتشر شده، می‌خوردند ومی نوشیدند و بزم می‌کردند، به‌سبب تمامی غنیمت عظیمی که از زمین فلسطینیان و از زمین یهودا آورده بودند."},{"v":17,"t":"و داود ایشان را از وقت شام تا عصر روز دیگر می‌زد که از ایشان احدی رهایی نیافت جز چهارصد مرد جوان که بر شتران سوار شده، گریختند."},{"v":18,"t":"و داود هرچه عمالقه گرفته بودند، بازگرفت و داود دو زن خود را بازگرفت."},{"v":19,"t":"و چیزی از ایشان مفقود نشد از خرد وبزرگ و از پسران و دختران و غنیمت و از همه چیزهایی که برای خود گرفته بودند، بلکه داودهمه را باز آورد."},{"v":20,"t":"و داود همه گوسفندان وگاوان خود را گرفت و آنها را پیش مواشی دیگرراندند و گفتند این است غنیمت داود."},{"v":21,"t":"و داود نزد آن دویست نفر که از شدت خستگی نتوانسته بودند در عقب داود بروند وایشان را نزد وادی بسور واگذاشته بودند آمد، وایشان به استقبال داود و به استقبال قومی که همراهش بودند بیرون آمدند، و چون داود نزدقوم رسید از سلامتی ایشان پرسید."},{"v":22,"t":"اما جمیع کسان شریر و مردان بلیعال از اشخاصی که با داودرفته بودند متکلم شده، گفتند: «چونکه همراه مانیامدند، از غنیمتی که باز آورده‌ایم چیزی به ایشان نخواهیم داد مگر به هر کس زن و فرزندان او را. پس آنها را برداشته، بروند.»"},{"v":23,"t":"لیکن داودگفت: «ای برادرانم چنین مکنید چونکه خداونداینها را به ما داده است و ما را حفظ نموده، آن فوج را که بر ما تاخت آورده بودند به‌دست ماتسلیم نموده است."},{"v":24,"t":"و کیست که در این امر به شما گوش دهد زیرا قسمت آنانی که نزد اسباب می‌مانند مثل قسمت آنانی که به جنگ می‌روند، خواهد بود و هر دو قسمت مساوی خواهند برد.»"},{"v":25,"t":"و از آن روز به بعد چنین شد که این را قاعده وقانون در اسرائیل تا امروز قرار داد."},{"v":26,"t":"و چون داود به صقلغ رسید، بعضی ازغنیمت را برای مشایخ یهودا و دوستان خودفرستاده، گفت: «اینک هدیه‌ای از غنیمت دشمنان خداوند برای شماست.»"},{"v":27,"t":"برای اهل بیت ئیل و اهل راموت جنوبی و اهل یتیر؛"},{"v":28,"t":"وبرای اهل عروعیر و اهل سفموت و اهل اشتموع؛"},{"v":29,"t":"و برای اهل راکال و اهل شهرهای یرحمئیلیان و اهل شهرهای قینیان؛"},{"v":30,"t":"و برای اهل حرما و اهل کورعاشان و اهل عتاق؛"},{"v":31,"t":"و برای اهل حبرون و جمیع مکانهایی که داود و کسانش درآنها آمد و رفت می‌کردند."}]},"31":{"fa":[{"v":1,"t":"و فلسطینیان با اسرائیل جنگ کردند ومردان اسرائیل از حضور فلسطینیان فرار کردند، و در کوه جلبوع کشته شده، افتادند."},{"v":2,"t":"و فلسطینیان، شاول و پسرانش را به سختی تعاقب نمودند، و فلسطینیان یوناتان و ابیناداب وملکیشوع پسران شاول را کشتند."},{"v":3,"t":"و جنگ برشاول سخت شد، و تیراندازان دور او را گرفتند وبه‌سبب تیراندازان به غایت دلتنگ گردید."},{"v":4,"t":"و شاول به سلاحدار خود گفت: «شمشیرخود را کشیده، آن را به من فرو بر مبادا این نامختونان آمده، مرا مجروح سازند و مرا افتضاح نمایند.» اما سلاحدارش نخواست زیرا که بسیاردر ترس بود. پس شاول شمشیر خود را گرفته، برآن افتاد."},{"v":5,"t":"و هنگامی که سلاحدارش شاول را دید که مرده است، او نیز بر شمشیر خود افتاده، با اوبمرد."},{"v":6,"t":"پس شاول و سه پسرش و سلاحدارش وجمیع کسانش نیز در آن روز با هم مردند."},{"v":7,"t":"وچون مردان اسرائیل که به آن طرف دره و به آن طرف اردن بودند، دیدند که مردان اسرائیل فرارکرده‌اند و شاول و پسرانش مرده‌اند، شهرهای خود را ترک کرده، گریختند و فلسطینیان آمده، در آنها ساکن شدند."},{"v":8,"t":"و در فردای آن روز، چون فلسطینیان برای برهنه کردن کشتگان آمدند، شاول و سه پسرش رایافتند که در کوه جلبوع افتاده بودند."},{"v":9,"t":"پس سر اورا بریدند و اسلحه‌اش را بیرون کرده، به زمین فلسطینیان، به هر طرف فرستادند تا به بتخانه های خود و به قوم مژده برسانند."},{"v":10,"t":"و اسلحه او را درخانه عشتاروت نهادند و جسدش را بر حصاربیتشان آویختند."},{"v":11,"t":"و چون ساکنان یابیش جلعاد، آنچه را که فلسطینیان به شاول کرده بودندشنیدند،"},{"v":12,"t":"جمیع مردان شجاع برخاسته، و تمامی شب سفر کرده، جسد شاول و اجسادپسرانش را از حصار بیتشان گرفتند، و به یابیش برگشته، آنها را در آنجا سوزانیدند."},{"v":13,"t":"واستخوانهای ایشان را گرفته، آنها را زیر درخت بلوطی که در یابیش است، دفن کردند و هفت روزروزه گرفتند."}]}});
